// ---- Company section graphs (Chart.js) ----
// Live Chart instances, keyed by canvas id, so we can tear them down and rebuild
// each time the modal is (re)populated.
const companyCharts = {};

// Currently selected graph time range, in months. null = all time. Persists
// across modal re-populations so the chosen filter sticks.
let companyChartRangeMonths = 12;

// Collapse the raw history into one point per (rounded) in-game month, keeping the
// latest snapshot for each month. Also derives net new customers per month from
// the cumulative total. Returns the full series (range filtering happens later).
function getCompanyMonthlySeries() {
    const byMonth = new Map();
    (gameState.history || []).forEach(snap => {
        const bucket = Math.max(1, Math.round(snap.month));
        const prev = byMonth.get(bucket);
        // Keep the latest snapshot for rate/level metrics, but ACCUMULATE one-time costs —
        // several decisions can land in the same month, each with its own spend.
        const oneTimeCost = (prev ? prev.oneTimeCost || 0 : 0) + (snap.oneTimeCost || 0);
        byMonth.set(bucket, { ...snap, monthBucket: bucket, oneTimeCost });
    });
    const series = Array.from(byMonth.values()).sort((a, b) => a.monthBucket - b.monthBucket);
    let prevCustomers = 0;
    series.forEach(s => {
        s.newCustomers = s.customers - prevCustomers; // can be negative if churn occurs
        prevCustomers = s.customers;
    });
    return series;
}

// Limit a monthly series to the most recent `months` months (null = keep all).
function filterSeriesByRange(series, months) {
    if (!months || !series.length) return series;
    const latest = series[series.length - 1].monthBucket;
    return series.filter(s => s.monthBucket > latest - months);
}

// Whole years of history the company has accumulated (min 1). Drives the slider's
// upper bound, so the control auto-scales as the game runs longer.
function getHistoryMaxYears() {
    const series = getCompanyMonthlySeries();
    const maxMonth = series.length ? series[series.length - 1].monthBucket : 1;
    return Math.max(1, Math.ceil(maxMonth / 12));
}

// Human label for a slider value. The far end (value === maxYears) means all time.
function rangeLabelText(value, maxYears) {
    if (value >= maxYears) return 'All time';
    return value === 1 ? 'Last 1 year' : `Last ${value} years`;
}

// Slider position the persisted range corresponds to, clamped to the current max.
function rangeSliderValue(maxYears) {
    if (companyChartRangeMonths === null) return maxYears;
    return Math.min(maxYears, Math.max(1, Math.round(companyChartRangeMonths / 12)));
}

// Handle slider movement: update the persisted range + label, then re-slice the
// data into the existing charts. We update in place (no destroy/recreate) so
// dragging stays smooth even though oninput fires continuously.
function onCompanyRangeSlider(value, maxYears) {
    value = Number(value);
    maxYears = Number(maxYears);
    companyChartRangeMonths = value >= maxYears ? null : value * 12;
    const text = rangeLabelText(value, maxYears);
    const label = document.getElementById('chartRangeValue');
    if (label) label.textContent = text;
    const slider = document.getElementById('chartRangeSlider');
    if (slider) slider.setAttribute('aria-valuetext', text); // announce "Last N years"
    updateCompanyCharts();
}

// Format an in-game month number as a "Y# M#" axis label.
function companyMonthLabel(month) {
    const year = Math.floor((month - 1) / 12) + 1;
    const m = ((month - 1) % 12) + 1;
    return year > 1 ? `Y${year} M${m}` : `M${m}`;
}

// (Re)create a single Chart on the given canvas, destroying any previous instance.
function makeCompanyChart(canvasId, config) {
    const canvas = document.getElementById(canvasId);
    if (!canvas || typeof Chart === 'undefined') return;
    if (companyCharts[canvasId]) {
        companyCharts[canvasId].destroy();
        delete companyCharts[canvasId];
    }
    companyCharts[canvasId] = new Chart(canvas.getContext('2d'), config);
}

// Extract the plotted arrays for the current series. The dataset order here is the
// contract shared by the create path (chart configs below) and the update path
// (updateCompanyCharts) — keep them in sync.
function computeChartData(series) {
    return {
        labels: series.map(s => companyMonthLabel(s.monthBucket)),
        financial: [
            series.map(s => Math.round(s.monthlyRevenue)),
            series.map(s => Math.round(s.monthlyBurn)),
            series.map(s => Math.round(s.netIncome)),
            series.map(s => Math.round(s.oneTimeCost || 0))
        ],
        customer: [
            series.map(s => s.newCustomers),
            series.map(s => s.customers)
        ],
        business: [
            series.map(s => s.confidence),
            series.map(s => s.credibility),
            series.map(s => s.reach)
        ],
        operations: [
            series.map(s => s.teamSize),
            series.map(s => s.stress)
        ]
    };
}

// Human description of the active range, for screen-reader summaries.
function describeChartRange() {
    if (companyChartRangeMonths === null) return 'all time';
    const years = Math.round(companyChartRangeMonths / 12);
    return years <= 1 ? 'the last year' : `the last ${years} years`;
}

// Refresh each canvas's aria-label so screen readers get a spoken summary of what
// the (otherwise opaque) chart currently shows. Re-run whenever the data changes.
function updateChartAccessibility(series) {
    const setAria = (id, text) => {
        const el = document.getElementById(id);
        if (el) el.setAttribute('aria-label', text);
    };
    if (series.length < 2) {
        ['financialChart', 'customerChart', 'businessChart', 'operationsChart']
            .forEach(id => setAria(id, 'Chart: not enough data yet — make a few decisions to see trends over time.'));
        return;
    }
    const last = series[series.length - 1];
    const range = describeChartRange();
    setAria('financialChart',
        `Financial trend over ${range}. Latest monthly revenue ${formatCurrency(last.monthlyRevenue)}, burn ${formatCurrency(last.monthlyBurn)}, net income ${formatCurrency(last.netIncome)}`
        + (last.oneTimeCost ? `, one-time costs ${formatCurrency(last.oneTimeCost)}` : '') + '.');
    setAria('customerChart',
        `Customer growth over ${range}. ${last.customers.toLocaleString()} total customers, ${Math.round(last.newCustomers).toLocaleString()} new in the latest month.`);
    setAria('businessChart',
        `Business development over ${range}. Confidence ${last.confidence}%, credibility ${last.credibility}%, reach ${last.reach}%.`);
    setAria('operationsChart',
        `Operations over ${range}. Team size ${last.teamSize}, founder stress ${last.stress}%.`);
}

// Show the "not enough data" overlay on each chart when the window has < 2 points,
// without destroying the chart instances underneath.
function applyChartEmptyState(isEmpty) {
    ['financialChartWrap', 'customerChartWrap', 'businessChartWrap', 'operationsChartWrap']
        .forEach(id => {
            const wrap = document.getElementById(id);
            if (wrap) wrap.classList.toggle('is-empty', isEmpty);
        });
}

// Full (re)build of all four charts. Used when the modal opens, since the canvases
// are recreated each time the body's innerHTML is rebuilt.
function renderCompanyCharts() {
    if (typeof Chart === 'undefined') return; // CDN failed to load — skip gracefully
    const series = filterSeriesByRange(getCompanyMonthlySeries(), companyChartRangeMonths);
    const d = computeChartData(series);

    const baseOptions = {
        responsive: true,
        maintainAspectRatio: false,
        // Short, eased animation so scrubbing the range slider morphs the charts
        // smoothly. Kept brief (vs. Chart.js's 1s default) so rapid drags keep up.
        animation: { duration: 250, easing: 'easeOutQuart' },
        interaction: { mode: 'index', intersect: false },
        plugins: {
            legend: { labels: { boxWidth: 12, font: { size: 11 } } },
            tooltip: { enabled: true }
        },
        elements: { line: { tension: 0.3, borderWidth: 2 }, point: { radius: 2, hoverRadius: 4 } },
        scales: {
            x: { grid: { display: false }, ticks: { font: { size: 10 }, maxRotation: 0, autoSkipPadding: 8 } },
            y: { beginAtZero: true, ticks: { font: { size: 10 } } }
        }
    };
    const currencyTicks = { callback: (v) => formatCurrency(v), font: { size: 10 } };

    // Financial: monthly revenue vs. burn vs. net income (lines, left axis) +
    // one-time costs (bars, right axis — they're lump spends, not a monthly rate)
    makeCompanyChart('financialChart', {
        type: 'line',
        data: {
            labels: d.labels,
            // Dataset order MUST match computeChartData().financial so the update path
            // (applyChartData maps array[i] → datasets[i]) stays in sync. Visual stacking
            // (bar behind lines) is handled by the `order` property, not array position.
            datasets: [
                { label: 'Revenue', data: d.financial[0], borderColor: '#10b981', backgroundColor: 'rgba(16,185,129,0.08)', fill: true, yAxisID: 'y', order: 0 },
                { label: 'Burn', data: d.financial[1], borderColor: '#ef4444', backgroundColor: 'rgba(239,68,68,0.05)', fill: false, yAxisID: 'y', order: 0 },
                { label: 'Net Income', data: d.financial[2], borderColor: '#3b82f6', backgroundColor: 'rgba(59,130,246,0.05)', fill: false, yAxisID: 'y', order: 0 },
                { type: 'bar', label: 'One-time cost', data: d.financial[3], backgroundColor: 'rgba(234,88,12,0.30)', borderColor: 'rgba(234,88,12,0.8)', borderWidth: 1, yAxisID: 'yOneTime', order: 1 }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                y: { beginAtZero: false, ticks: currencyTicks },
                yOneTime: { type: 'linear', position: 'right', beginAtZero: true, grid: { drawOnChartArea: false }, ticks: currencyTicks }
            },
            plugins: {
                ...baseOptions.plugins,
                tooltip: { callbacks: { label: (c) => `${c.dataset.label}: ${formatCurrency(c.parsed.y)}` + (c.dataset.label === 'One-time cost' ? '' : '/mo') } }
            }
        }
    });

    // Customer: total customers (line, left axis) + net new customers/mo (bars, right axis)
    makeCompanyChart('customerChart', {
        type: 'bar',
        data: {
            labels: d.labels,
            datasets: [
                { type: 'bar', label: 'New / mo', data: d.customer[0], backgroundColor: 'rgba(96,165,250,0.45)', borderColor: 'rgba(96,165,250,0.85)', borderWidth: 1, yAxisID: 'yNew', order: 1 },
                { type: 'line', label: 'Total Customers', data: d.customer[1], borderColor: '#2563eb', backgroundColor: 'rgba(37,99,235,0.10)', fill: true, yAxisID: 'yTotal', order: 0 }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                yTotal: { type: 'linear', position: 'left', beginAtZero: true, ticks: { font: { size: 10 } } },
                yNew: { type: 'linear', position: 'right', beginAtZero: true, grid: { drawOnChartArea: false }, ticks: { precision: 0, font: { size: 10 } } }
            },
            plugins: {
                ...baseOptions.plugins,
                tooltip: { callbacks: { label: (c) => `${c.dataset.label}: ${Math.round(c.parsed.y).toLocaleString()}` } }
            }
        }
    });

    // Business Development: confidence, credibility, reach (all 0–100)
    makeCompanyChart('businessChart', {
        type: 'line',
        data: {
            labels: d.labels,
            datasets: [
                { label: 'Confidence', data: d.business[0], borderColor: '#7c3aed', backgroundColor: 'rgba(124,58,237,0.06)', fill: false },
                { label: 'Credibility', data: d.business[1], borderColor: '#db2777', backgroundColor: 'rgba(219,39,119,0.06)', fill: false },
                { label: 'Reach', data: d.business[2], borderColor: '#0891b2', backgroundColor: 'rgba(8,145,178,0.06)', fill: false }
            ]
        },
        options: {
            ...baseOptions,
            scales: { x: baseOptions.scales.x, y: { beginAtZero: true, max: 100, ticks: { font: { size: 10 } } } }
        }
    });

    // Operations: team size (count, left axis) vs. founder stress (%, right axis)
    makeCompanyChart('operationsChart', {
        type: 'line',
        data: {
            labels: d.labels,
            datasets: [
                { label: 'Team Size', data: d.operations[0], borderColor: '#d97706', backgroundColor: 'rgba(217,119,6,0.10)', fill: true, yAxisID: 'yTeam' },
                { label: 'Stress %', data: d.operations[1], borderColor: '#dc2626', backgroundColor: 'rgba(220,38,38,0.05)', fill: false, yAxisID: 'yStress' }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                yTeam: { type: 'linear', position: 'left', beginAtZero: true, ticks: { precision: 0, font: { size: 10 } }, title: { display: false } },
                yStress: { type: 'linear', position: 'right', beginAtZero: true, max: 100, grid: { drawOnChartArea: false }, ticks: { font: { size: 10 } } }
            }
        }
    });

    applyChartEmptyState(series.length < 2);
    updateChartAccessibility(series);
}

// Push freshly sliced data into one existing chart and repaint without animation.
function applyChartData(canvasId, labels, dataArrays) {
    const chart = companyCharts[canvasId];
    if (!chart) return;
    chart.data.labels = labels;
    dataArrays.forEach((arr, i) => {
        if (chart.data.datasets[i]) chart.data.datasets[i].data = arr;
    });
    chart.update(); // uses the chart's short configured animation (see baseOptions)
}

// Lightweight redraw used while dragging the range slider: re-slice the series and
// update the existing chart instances in place instead of tearing them down.
function updateCompanyCharts() {
    if (typeof Chart === 'undefined') return;
    // If the charts haven't been built yet (e.g. first open), fall back to a full build.
    if (!companyCharts.financialChart) { renderCompanyCharts(); return; }
    const series = filterSeriesByRange(getCompanyMonthlySeries(), companyChartRangeMonths);
    const d = computeChartData(series);
    applyChartData('financialChart', d.labels, d.financial);
    applyChartData('customerChart', d.labels, d.customer);
    applyChartData('businessChart', d.labels, d.business);
    applyChartData('operationsChart', d.labels, d.operations);
    applyChartEmptyState(series.length < 2);
    updateChartAccessibility(series);
}

// ---- Company story (shareable narrative) ----
// Stitches gameState + the player's selections into a natural-language summary of
// the company, surfaced on the Story tab with a share button. Phrase tables below
// map specific card titles to story fragments; unmapped cards just don't contribute
// a clause, so the story stays readable no matter what's been picked.

// Notable business-model cards → a "we're <building ...>" clause (most recent wins).
const STORY_MODEL_PHRASES = {
    "Freemium SaaS": "building a freemium SaaS",
    "Enterprise Licensing": "selling enterprise software",
    "Marketplace Commission": "running a marketplace",
    "Subscription Tiers": "running a subscription business",
    "Global Expansion": "scaling a global business"
};

// Product cards → a short "with ..." clause describing what we've built.
const STORY_PRODUCT_PHRASES = {
    "Real-time Collaboration": "collaboration built in",
    "AI-Powered Recommendations": "an AI recommendation engine",
    "Mobile Application": "native mobile apps",
    "Integration Marketplace": "deep third-party integrations",
    "Customizable Workflows": "fully customizable workflows",
    "Multi-Format Export": "open data import and export",
    "Focus Mode": "a distraction-free focus mode",
    "Carbon Calculator Integration": "a built-in carbon tracker",
    "Proprietary Hardware": "our own custom hardware"
};

// ESG cards → a values clause ("We ...") for the story's mission sentence.
const STORY_VALUES_PHRASES = {
    "Profit & Purpose Balance": "We believe in balancing profit with purpose",
    "1% for the Planet": "We pledge 1% of revenue back to the planet",
    "Carbon Neutral Pledge": "We're committed to carbon neutrality",
    "Divest from Big Oil": "We've turned our back on fossil fuels",
    "Circular Economy Pledge": "We design out waste with a circular model",
    "B-Corp Pitch Deck": "We're on the path to B-Corp certification",
    "Ethical AI Guidelines": "We hold ourselves to clear ethical-AI standards",
    "Community Volunteer Program": "We give our team paid time to give back",
    "Sustainable by Design": "Sustainability is built into everything we make",
    "Open Knowledge Sharing": "We share our tools and playbooks openly",
    "Supply Chain Audit": "We hold our supply chain to ethical standards"
};

// Business cards that represent a corporate partnership / channel deal — counted
// for the "with N corporate partners" traction line.
const STORY_PARTNER_TITLES = new Set([
    "Enterprise Licensing",
    "International Distribution Deal",
    "Distributed Operations",
    "Global Expansion"
]);

// Oxford-style list join: ["a"] -> "a"; ["a","b"] -> "a and b"; 3+ -> "a, b, and c".
function joinStoryList(items) {
    if (items.length <= 1) return items[0] || '';
    if (items.length === 2) return `${items[0]} and ${items[1]}`;
    return `${items.slice(0, -1).join(', ')}, and ${items[items.length - 1]}`;
}

// Rough, game-flavored company valuation: a growth-scaled revenue multiple (3x–8x
// ARR), with a customer-base floor so pre/low-revenue companies still read sensibly.
function estimateValuation() {
    const arr = gameState.monthlyRevenue * 12;
    const multiple = 3 + Math.min(5, gameState.growth / 20);
    return Math.max(arr * multiple, gameState.customers * 120, 50000);
}

// "N years/months after founding" from the elapsed in-game months. In-game time
// accrues in fractional months, so round for display (raw values look like
// "1.2999999999999998 months").
function companyAgePhrase() {
    const months = Math.max(0, gameState.currentMonth - 1);
    if (months < 1) return 'fresh out of founding';
    if (months < 12) {
        const m = Math.round(months);
        return `just ${m} month${m === 1 ? '' : 's'} after founding`;
    }
    const years = Math.round(months / 12 * 10) / 10; // one decimal, float-safe
    const label = Number.isInteger(years) ? String(years) : years.toFixed(1);
    return `${label} year${years === 1 ? '' : 's'} after founding`;
}

// Distill the whole run into a single shareable "founder archetype" — the identity
// hook for the Story tab ("what kind of founder are you?"). Rules are checked in
// priority order, most defining first, so the first match wins; the final entry is
// an always-true catch-all. Each returns { emoji, name, blurb }.
function deriveFounderArchetype() {
    const gs = gameState;
    const decisions = (gs.selectedCards || []).filter(c => c.category !== 'outcome');
    const esgCount = decisions.filter(c => c.category === 'esg').length;
    const challengesSurvived = (gs.selectedCards || [])
        .filter(c => c.category === 'outcome' && c.type === 'challenge').length;
    const netIncome = gs.monthlyRevenue - gs.monthlyBurn;
    const profitable = gs.monthlyRevenue > 0 && netIncome > 0;
    const runwayMonths = gs.runway > 0 ? gs.runway / Math.max(1, gs.monthlyBurn) : 0;
    const monthsElapsed = Math.max(0, gs.currentMonth - 1);

    if (decisions.length < 3)
        return { emoji: '🌱', name: 'The Dreamer', blurb: 'Still getting the idea off the ground.', colors: ['#16a34a', '#15803d'] };
    if (monthsElapsed >= 4 && !profitable && runwayMonths < 4)
        return { emoji: '⛽', name: 'Running on Fumes', blurb: 'Betting it all on the next move.', colors: ['#ef4444', '#b91c1c'] };
    if (profitable && gs.monthlyRevenue >= 40000)
        return { emoji: '💸', name: 'The Cash Machine', blurb: 'Printing money, month after month.', colors: ['#059669', '#047857'] };
    if (gs.growth >= 40 && netIncome < 0)
        return { emoji: '🚀', name: 'The Rocketship', blurb: 'Growth at all costs — and the costs are real.', colors: ['#3b82f6', '#1e3a8a'] };
    if (esgCount >= 3 || (esgCount >= 2 && gs.credibility >= 50))
        return { emoji: '🌍', name: 'The Mission-Driven Founder', blurb: 'Proof you can do well by doing good.', colors: ['#0d9488', '#0f766e'] };
    if (gs.reach >= 45 && gs.engagement < 25)
        return { emoji: '📣', name: 'The Hype Machine', blurb: "Everyone's heard of you — now make them stay.", colors: ['#f97316', '#ea580c'] };
    if (gs.engagement >= 55)
        return { emoji: '❤️', name: 'The Cult Favorite', blurb: 'A loyal crowd that would follow you anywhere.', colors: ['#ec4899', '#be185d'] };
    if (gs.teamSize >= 8)
        return { emoji: '🏛️', name: 'The Empire Builder', blurb: 'Building something built to last.', colors: ['#6366f1', '#4338ca'] };
    if (profitable && gs.teamSize <= 5)
        return { emoji: '🥾', name: 'The Bootstrapper', blurb: 'Lean, profitable, and beholden to no one.', colors: ['#d97706', '#b45309'] };
    if (challengesSurvived >= 3)
        return { emoji: '🛡️', name: 'The Survivor', blurb: 'Took the hits and kept on building.', colors: ['#0ea5e9', '#0369a1'] };
    if (gs.teamSize === 1 && monthsElapsed >= 9)
        return { emoji: '🐺', name: 'The Lone Wolf', blurb: 'One founder, no excuses.', colors: ['#64748b', '#334155'] };
    return { emoji: '🧭', name: 'The Operator', blurb: 'Steadily turning decisions into a real company.', colors: ['#1e3a8a', '#3730a3'] };
}

// Outcome cards whose *title* survives into selectedCards (challenges, milestones and
// notable positives all go through acknowledgeOutcome, which keeps the original card)
// map here to a story beat. NB: opportunity cards do NOT — handleOpportunityChoice
// records the chosen option's text, not the opportunity's name — so raises/pivots are
// mined from the history time-series and the decision log instead (see below).
// Each entry: { priority, mood, clause(name, date) -> first-person fragment }. The
// fragment weaves the date in itself, starts lowercase and ends without a period — the
// composer capitalizes it and stitches it into a sentence. Higher priority survives the
// "most dramatic beats" cut on long runs.
const STORY_MILESTONE_BEATS = {
    "First $1K MRR! 🎉":             { priority: 6, mood: 'up', clause: (n, d) => `in ${d}, we banked our first $1K of recurring revenue — small money, enormous proof` },
    "Ramen Profitability Achieved":  { priority: 7, mood: 'up', clause: (n, d) => `by ${d}, we'd reached ramen profitability and were finally paying our own way` },
    "Industry Award":                { priority: 5, mood: 'up', clause: (n, d) => `in ${d}, the industry took notice and handed us an award` },
    "Viral Product Demo":            { priority: 5, mood: 'up', clause: (n, d) => `a demo of ours caught fire in ${d} and raced across the internet` },
    "Partnership Goldmine":          { priority: 5, mood: 'up', clause: (n, d) => `in ${d}, a breakthrough partnership fell into place` },
    "Audience Takes Off":            { priority: 4, mood: 'up', clause: (n, d) => `around ${d}, our audience finally caught on and took off` },
    "Key Hire Success":              { priority: 4, mood: 'up', clause: (n, d) => `one pivotal hire in ${d} quietly changed everything for us` }
};

// Compose the shareable story as flowing, first-person prose — the founder telling the
// tale of the company they built, the way they'd write it in a social post. Rather than
// four fixed slots keyed off card categories, it mines the *whole record* for turning
// points and keeps only the most dramatic, so two players with the same card count but
// different trajectories get genuinely different stories. Sources:
//   • the founding decision (the aim) and the present-day snapshot — the two anchors;
//   • the per-month history time-series (getCompanyMonthlySeries): the profit flip, a
//     capital raise (a one-step jump UP in runway), a near-death runway dip + recovery,
//     the single biggest growth month, a survived burnout stress spike;
//   • the decision log: first hire/revenue, a business-model pivot;
//   • outcome cards: a weathered challenge, plus the named milestones/wins above.
// Each middle beat is a lowercase, date-woven clause with a `mood` (up/down/neutral);
// the composer keeps the top few, orders them chronologically, and stitches them into a
// paragraph with mood-aware transitions ("But we clawed back…", "Then trouble struck…").
// The tone is deliberately plucky and a little self-mythologizing — it's the founder's
// own highlight reel — and invents harmless colour (caffeine, case studies) since the
// whole company is fictional. Returns an array of paragraph strings (the "acts"):
// founding, the middle drama (omitted on brand-new runs), and where we stand now.
function generateStoryArc(cards, archetype) {
    const name = gameState.companyName || 'our startup';
    const decisions = cards.filter(c => c.category !== 'outcome');
    if (!decisions.length) return [];

    const series = (typeof getCompanyMonthlySeries === 'function') ? getCompanyMonthlySeries() : [];
    const founded = new Date(gameState.founded);
    // "Month YYYY" reads better in prose than the card's "Mon DD, YYYY".
    const longDate = (d) => d.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
    const dateOfMonth = (m) => {
        const d = new Date(founded);
        d.setMonth(d.getMonth() + Math.max(0, Math.round(m) - 1));
        return longDate(d);
    };
    const dateOfCard = (c) => (c.selectedMonth ? dateOfMonth(c.selectedMonth) : (c.selectedAt || 'those early days'));
    const cap = (s) => (s ? s.charAt(0).toUpperCase() + s.slice(1) : s);
    const pick = (arr, i) => arr[Math.abs(i) % arr.length];

    // Middle beats: { sort, priority, mood, clause }. The two anchors are composed
    // separately as the opening and closing paragraphs.
    const mids = [];

    // ── First building blocks: first hire and/or first revenue, in the order they happened. ──
    const hireIdx = cards.findIndex(c => isHireCard(c));
    const revIdx = cards.findIndex(c => c.impact && c.impact.monthlyRevenue > 0);
    if (hireIdx !== -1 || revIdx !== -1) {
        const ev = [];
        if (hireIdx !== -1) ev.push({ idx: hireIdx, card: cards[hireIdx], kind: 'hire' });
        if (revIdx !== -1) ev.push({ idx: revIdx, card: cards[revIdx], kind: 'rev' });
        ev.sort((a, b) => a.idx - b.idx);
        const phrases = ev.map(e => e.kind === 'hire'
            ? `our first hire — a ${e.card.title} — came aboard`
            : `the first dollars trickled in through ${e.card.title}`);
        mids.push({
            sort: ev[0].card.selectedMonth || 1, priority: 3, mood: 'up',
            clause: `we found our feet in ${dateOfCard(ev[0].card)} as ${joinStoryList(phrases)}`
        });
    }

    // ── Pivot: the business model actually changed across the run. ──
    const modelCards = decisions.filter(c => c.category === 'business' && STORY_MODEL_PHRASES[c.title]);
    if (modelCards.length >= 2) {
        const from = modelCards[0], to = modelCards[modelCards.length - 1];
        if (STORY_MODEL_PHRASES[from.title] !== STORY_MODEL_PHRASES[to.title]) {
            mids.push({
                sort: to.selectedMonth || 2, priority: 8, mood: 'neutral',
                clause: `in ${dateOfCard(to)}, with our first plan sputtering, we made the kind of pivot they write case studies about — trading ${STORY_MODEL_PHRASES[from.title]} for ${STORY_MODEL_PHRASES[to.title]}`
            });
        }
    }

    // ── History-mined turning points (need ≥2 monthly points to compare). ──
    if (series.length >= 2) {
        // Capital raised: a one-step jump UP in runway. Runway otherwise only falls via
        // burn, so a big positive delta is a cash injection (a round lands as oneTimeRevenue).
        let raise = null;
        for (let i = 1; i < series.length; i++) {
            const jump = series[i].runway - series[i - 1].runway;
            if (jump >= 250000 && (!raise || jump > raise.jump)) raise = { jump, m: series[i].monthBucket };
        }
        if (raise) mids.push({
            sort: raise.m, priority: 9, mood: 'up',
            clause: `in ${dateOfMonth(raise.m)}, investors came calling, and ${formatCurrency(raise.jump)} in fresh capital hit our account — rocket fuel for everything that followed`
        });

        // First profit: net income crosses from ≤0 up to >0.
        for (let i = 0; i < series.length; i++) {
            if (series[i].netIncome > 0 && (i === 0 || series[i - 1].netIncome <= 0)) {
                mids.push({
                    sort: series[i].monthBucket, priority: 8, mood: 'up',
                    clause: `by ${dateOfMonth(series[i].monthBucket)}, our books had tipped into the black, and we were finally earning more than we burned`
                });
                break;
            }
        }

        // Near-death + recovery: runway dipped to a scary low, then climbed back. Most
        // dramatic beat in the deck, so it outranks everything else.
        let low = null;
        series.forEach(s => {
            const months = s.runway / Math.max(1, s.monthlyBurn);
            if (s.runway > 0 && (!low || months < low.months)) low = { months, m: s.monthBucket };
        });
        const lastSeries = series[series.length - 1];
        const lastMonths = lastSeries.runway / Math.max(1, lastSeries.monthlyBurn);
        if (low && low.months < 2 && low.m < lastSeries.monthBucket && lastMonths > low.months + 1) {
            const wk = Math.max(1, Math.round(low.months * 4.345));
            // End on the brink — the recovery is delivered by the next up-beat's
            // transition (or, if this is the last beat, by the present-day paragraph),
            // so we don't say "clawed back" twice.
            mids.push({
                sort: low.m, priority: 10, mood: 'down',
                clause: `by ${dateOfMonth(low.m)}, our runway had withered to barely ${wk} week${wk === 1 ? '' : 's'} — close enough to the edge to look right over it`
            });
        }

        // Breakout month: the single biggest one-month customer gain.
        let grow = null;
        series.forEach(s => { if (s.newCustomers > 0 && (!grow || s.newCustomers > grow.n)) grow = { n: s.newCustomers, m: s.monthBucket }; });
        if (grow && grow.n >= 50) mids.push({
            sort: grow.m, priority: 6, mood: 'up',
            clause: `${dateOfMonth(grow.m)} became our breakout month, ${Math.round(grow.n).toLocaleString()} new customers rushing in at once`
        });

        // Burnout dodged: stress spiked high, then eased back off the ceiling.
        let peak = null;
        series.forEach(s => { if (!peak || s.stress > peak.stress) peak = { stress: s.stress, m: s.monthBucket }; });
        if (peak && peak.stress >= 75 && peak.m < lastSeries.monthBucket && lastSeries.stress < peak.stress - 15) {
            mids.push({
                sort: peak.m, priority: 5, mood: 'down',
                clause: `around ${dateOfMonth(peak.m)}, we came within inches of burning out, the stress pinned at ${Math.round(peak.stress)}%, before pulling back from the brink`
            });
        }
    }

    // ── A weathered challenge: the first storm, with a count when there's been more. ──
    const challenges = cards.filter(c => c.category === 'outcome' && c.type === 'challenge');
    if (challenges.length) {
        const first = challenges[0];
        const more = challenges.length > 1 ? `, just one of ${challenges.length} storms we'd survive` : '';
        mids.push({
            sort: first.selectedMonth || 2, priority: 7, mood: 'down',
            clause: `in ${dateOfCard(first)}, “${first.title}” nearly knocked the whole thing over — but we weathered it${more}`
        });
    }

    // ── Named milestones / standout wins (title preserved on the card). ──
    cards.forEach(c => {
        if (c.category !== 'outcome') return;
        const b = STORY_MILESTONE_BEATS[c.title];
        if (!b) return;
        mids.push({ sort: c.selectedMonth || 2, priority: b.priority, mood: b.mood, clause: b.clause(name, dateOfCard(c)) });
    });

    // ── Opening paragraph. We keep several openings and lock to one per company —
    // seeded by the founding instant, which never changes for a run — so the hook varies
    // across startups but stays put every time you reopen this one. The values-led
    // opening unlocks once an ESG card has been played; the rest are always available. ──
    let foundingAim = null;
    for (let i = 0; i < decisions.length; i++) {
        if (decisions[i].category === 'business' && STORY_MODEL_PHRASES[decisions[i].title]) {
            foundingAim = STORY_MODEL_PHRASES[decisions[i].title]; // gerund: "building a freemium SaaS"
            break;
        }
    }
    const aimClause = foundingAim ? `a wild bet on ${foundingAim}` : `chasing an idea the rest of the world hadn't caught up to yet`;
    const date0 = longDate(founded);
    let valuesPhrase = '';
    for (let i = decisions.length - 1; i >= 0; i--) {
        if (STORY_VALUES_PHRASES[decisions[i].title]) { valuesPhrase = STORY_VALUES_PHRASES[decisions[i].title]; break; }
    }
    const valuesLower = valuesPhrase ? valuesPhrase.charAt(0).toLowerCase() + valuesPhrase.slice(1) : '';
    const openings = [
        { ok: true, text: () => `Every great company starts with a leap. We took ours in ${date0} and called it ${name} — ${aimClause}, backed by little more than conviction and caffeine.` },
        { ok: !!valuesPhrase, text: () => `At ${name}, we stand for something bigger than the bottom line: ${valuesLower}. We've believed that since the beginning, back in ${date0}.` },
        { ok: true, text: () => `They told us it couldn't be done — or worse, that it wasn't worth doing. We started ${name} in ${date0} anyway, ${aimClause}.` },
        { ok: true, text: () => `${name} didn't begin with a boardroom or a war chest. It started in ${date0} with ${aimClause} and a stubborn refusal to quit.` },
        { ok: true, text: () => `This is the story of ${name} — the company we started in ${date0}, ${aimClause}.` }
    ];
    // Seed from the run's founding instant, then walk forward to the next eligible
    // opening (the first is always eligible, so this always terminates).
    let oi = Math.abs(Math.floor(founded.getTime() / 60000)) % openings.length;
    for (let k = 0; k < openings.length && !openings[oi].ok; k++) oi = (oi + 1) % openings.length;
    const openP = openings[oi].text();

    // ── Middle paragraph: keep the most dramatic beats, order them in time, stitch them
    // together with mood-aware transitions so it reads as one running account. ──
    const kept = mids.sort((a, b) => b.priority - a.priority).slice(0, 4).sort((a, b) => a.sort - b.sort);
    // Transition into a beat. `gap` is the months since the previous kept beat (sort is
    // an in-game month number). The gap leads once beats are far apart — runs can span
    // many years, so a short-gap phrase like "Soon after," would lie about a multi-year
    // jump. Only when beats are genuinely close (< 6 months) do we fall back to the
    // mood-aware turns; the exact dates live in the clauses regardless.
    const connect = (i, mood, prev, gap) => {
        if (gap >= 24) return pick(['Years later, ', 'A long road later, ', 'Much further down the line, '], i);
        if (gap >= 12) return pick(['A year on, ', 'The following year, ', 'Some time later, '], i);
        if (gap >= 6) return pick(['Months later, ', 'In the months that followed, ', 'Before long, '], i);
        if (mood === 'up' && prev === 'down') return pick(['Then the tide turned — ', 'But we clawed back: ', 'Against the odds, '], i);
        if (mood === 'down' && prev !== 'down') return pick(['Then trouble struck: ', "But it wasn't all smooth — ", 'The ground shifted under us: '], i);
        return pick(['Then ', 'Soon after, ', 'And then '], i);
    };
    let midP = '';
    if (kept.length) {
        midP = kept.map((b, i) => i === 0
            ? cap(b.clause) + '.'
            : connect(i, b.mood, kept[i - 1].mood, b.sort - kept[i - 1].sort) + b.clause + '.'
        ).join(' ');
    }

    // ── Closing paragraph. The archetype sign-off is shared; the lead-in is either
    // the present-tense "where we stand now" (a live run) or, once the run has ended,
    // a past-tense retrospective keyed off how it ended (the narrative half of the
    // post-mortem — the verdict block above carries the numbers). ──
    // companyAgePhrase() reads "N years after founding"; reshape to "N years in".
    const ageNow = companyAgePhrase().replace('after founding', 'in');
    const signoff = (archetype && archetype.name ? ` Call us what we are: ${archetype.name}.` : '')
        + (archetype && archetype.blurb ? ` ${archetype.blurb}` : '');

    const outcome = (typeof getRunOutcome === 'function') ? getRunOutcome() : null;
    let leadIn;
    if (outcome) {
        const endDate = dateOfMonth(gameState.currentMonth);
        const custStrong = gameState.customers > 0
            ? `${gameState.customers.toLocaleString()} customer${gameState.customers === 1 ? '' : 's'}`
            : 'a handful of believers';
        if (outcome === 'exit') {
            leadIn = `Then, in ${endDate}, the offer came — and we took it. We sold ${name} for `
                + `${formatCurrency(gameState.exitSalePrice || 0)}, ${custStrong} and ${ageNow}. `
                + `We'd built something worth buying.`;
        } else if (outcome === 'ideaFlop') {
            leadIn = `By ${endDate}, ${ageNow}, we had to admit it: the idea never found its people. `
                + `We built, and waited, and built some more, but ${custStrong} was as far as it ever went — `
                + `and we finally chose to stop.`;
        } else if (outcome === 'burnout') {
            leadIn = `By ${endDate}, ${ageNow}, it wasn't the company that gave out — it was us. `
                + `The stress had been pinned at the ceiling for months, and no business is worth your health. `
                + `We stepped away to put ourselves back together.`;
        } else { // insolvency
            leadIn = `By ${endDate}, ${ageNow}, the money was gone. We'd grown to ${custStrong}, `
                + `but the burn always ran ahead of the revenue, and one month there was nothing left to make payroll. `
                + `${name} closed its doors.`;
        }
    } else {
        const cred = gameState.credibility;
        let standing;
        if (cred >= 60) standing = 'a genuine leader in our space';
        else if (cred >= 35) standing = 'a company people actually know';
        else if (cred >= 15) standing = 'a rising name with real momentum';
        else standing = 'scrappy, unproven, and utterly unbowed';
        const tractionWords = [];
        if (gameState.customers > 0) tractionWords.push(`${gameState.customers.toLocaleString()} customer${gameState.customers === 1 ? '' : 's'} strong`);
        tractionWords.push(`a team of ${gameState.teamSize}`);
        tractionWords.push(`a valuation circling ${formatCurrency(estimateValuation())}`);
        let momentum = ' And the next chapter is still unwritten.';
        if (series.length >= 3) {
            const recentGain = series[series.length - 1].customers - series[series.length - 3].customers;
            if (recentGain > 0) momentum = " And we're only picking up speed.";
            else if (recentGain < 0) momentum = " The last stretch has tested us — but we're still standing.";
        }
        leadIn = `Today, ${ageNow}, we stand as ${standing} — ${joinStoryList(tractionWords)}.${momentum}`;
    }
    // Archetype blurbs already end in a period, so don't add one.
    const closeP = leadIn + signoff;

    const paragraphs = [openP];
    if (midP) paragraphs.push(midP);
    paragraphs.push(closeP);
    return paragraphs;
}

// Assemble the narrative. Returns { paragraph, shareText, archetype, arc } or null if
// the player hasn't made any real decisions yet (so the empty state can show instead).
// `paragraph` is the snapshot baked into the share image; `arc` is the chapter timeline
// shown (and copied) on the Story tab.
function generateCompanyStory() {
    const cards = gameState.selectedCards.filter(c => c.category !== 'outcome');
    if (!cards.length) return null;

    const name = gameState.companyName || 'our startup';
    const sentences = [];

    // 1) Who we are + what we build.
    const teamPhrase = gameState.teamSize <= 1 ? 'a solo founder' : `a team of ${gameState.teamSize}`;

    let modelPhrase = 'building a startup';
    for (let i = cards.length - 1; i >= 0; i--) {
        if (cards[i].category === 'business' && STORY_MODEL_PHRASES[cards[i].title]) {
            modelPhrase = STORY_MODEL_PHRASES[cards[i].title];
            break;
        }
    }

    const productClauses = [];
    const seenProduct = new Set();
    for (let i = cards.length - 1; i >= 0 && productClauses.length < 2; i--) {
        const phrase = STORY_PRODUCT_PHRASES[cards[i].title];
        if (phrase && !seenProduct.has(cards[i].title)) {
            seenProduct.add(cards[i].title);
            productClauses.push(phrase);
        }
    }
    const productPhrase = productClauses.length ? ` with ${joinStoryList(productClauses)}` : '';
    sentences.push(`We're ${name}, ${teamPhrase} ${modelPhrase}${productPhrase}.`);

    // 2) Values / mission (only if a values card has been picked).
    for (let i = cards.length - 1; i >= 0; i--) {
        if (STORY_VALUES_PHRASES[cards[i].title]) {
            sentences.push(`${STORY_VALUES_PHRASES[cards[i].title]}.`);
            break;
        }
    }

    // 3) Market position + traction (partners, customers).
    const cred = gameState.credibility;
    let position;
    if (cred >= 60) position = "We're a recognized leader in our space";
    else if (cred >= 35) position = "We've built a real reputation in our industry";
    else if (cred >= 15) position = "We're a rising name in our market";
    else position = "We're still earning our place in the market";

    const partnerCount = cards.filter(c => STORY_PARTNER_TITLES.has(c.title)).length;
    const traction = [];
    if (partnerCount > 0) traction.push(`${partnerCount} corporate partner${partnerCount === 1 ? '' : 's'}`);
    if (gameState.customers > 0) traction.push(`${gameState.customers.toLocaleString()} customer${gameState.customers === 1 ? '' : 's'}`);
    sentences.push(traction.length ? `${position}, with ${joinStoryList(traction)}.` : `${position}.`);

    // 4) Engagement (skipped when there's nothing flattering to say).
    const eng = gameState.engagement;
    if (eng >= 60) sentences.push('Our users are highly engaged.');
    else if (eng >= 35) sentences.push('Our users are solidly engaged.');
    else if (eng >= 15) sentences.push("We're working hard to deepen engagement.");

    // 5) Finances + age.
    const valuation = estimateValuation();
    const finance = gameState.totalRevenue > 0
        ? `We're valued around ${formatCurrency(valuation)} on ${formatCurrency(gameState.totalRevenue)} of lifetime revenue`
        : `We're valued around ${formatCurrency(valuation)} and still pre-revenue`;
    sentences.push(`${finance}, ${companyAgePhrase()}.`);

    const paragraph = sentences.join(' ');
    const archetype = deriveFounderArchetype();

    // The shareable copy is the first-person story arc (the social-post text that rides
    // alongside the image), not the image's snapshot paragraph — so it reads as the
    // founder's own telling. `arc` is an array of paragraph strings.
    const arc = generateStoryArc(gameState.selectedCards, archetype);
    const shareText = `${archetype.emoji} ${name} — ${archetype.name}\n\n`
        + arc.join('\n\n')
        + `\n\nWhat kind of founder are you? → https://dlightning.org/games`;
    return { paragraph, shareText, archetype, arc };
}

// Short age label for the image card's stat chip, e.g. "8mo" or "4.4y".
function storyAgeShort() {
    const months = Math.max(0, gameState.currentMonth - 1);
    if (months < 12) return `${Math.round(months)}mo`;
    const years = Math.round(months / 12 * 10) / 10; // one decimal, float-safe
    return `${Number.isInteger(years) ? years : years.toFixed(1)}y`;
}

// Brand wordmark for the share card header. Inlined (not fetched) so it works under
// file:// and — being a data: URL — never taints the canvas on export. Recolored to
// white at load so it reads on any themed band: a root fill covers the (black)
// "startup" glyphs and the `.e` rule covers the (green) "cards" glyphs. Source of
// truth: svg/startupCards.svg — keep this in sync if the logo ever changes.
const STORY_LOGO_SVG = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1193.52 546.68"><defs><style>.d{fill:none;}.e{fill:#059669;}</style></defs><g id="b" shape-rendering="geometricPrecision"><rect class="d" x="98.7" y="49.46" width="0" height="7.27"/><path d="M6.26,196.41h46.53c-1.85,23.73,17.87,40.68,47.46,40.68,25.58,0,42.22-12.63,43.45-28.35,4.01-46.53-135.59-7.4-127.88-94.6,3.7-43.14,42.83-72.72,95.83-72.72s89.06,32.05,85.36,76.11h-44.99c2.16-21.57-16.02-36.98-42.52-36.98-24.34,0-41.6,11.4-42.83,26.81-4.01,44.68,135.9,6.16,128.19,93.99-3.7,43.76-43.76,74.88-99.53,74.88S2.25,242.63,6.26,196.41Z"/><path d="M241.69,145.87h-22.19l3.08-35.13h24.34l8.63-39.75h38.83l-3.39,39.75h35.75l-3.08,35.13h-35.75l-5.85,66.87c-1.23,13.25,6.16,22.19,19.11,22.19,4.31,0,11.09-.92,16.33-2.16l-3.39,36.98c-9.55,3.08-22.19,4.93-32.05,4.93-31.43,0-49.61-23.73-46.53-57.32l6.16-71.49Z"/><path d="M483.28,110.74h46.22l-13.87,157.77h-46.22l1.85-21.88c-13.87,17.56-33.59,28.04-56.08,28.04-44.37,0-72.42-35.13-68.1-85.05,4.62-49.92,38.83-85.05,83.2-85.05,22.5,0,40.37,10.48,51.15,28.04l1.85-21.88ZM475.88,189.63c2.46-25.58-13.25-44.37-37.29-44.37s-42.83,18.8-45.3,44.37c-2.16,25.58,13.56,44.37,37.59,44.37s42.83-18.8,44.99-44.37Z"/><path d="M674.95,108.89l-3.39,40.98c-8.63-3.7-18.8-5.85-25.58-5.85-20.03,0-34.51,16.95-36.67,40.68l-7.4,83.82h-46.22l13.87-157.77h44.37l-1.85,20.03c10.79-15.72,26.81-25.88,44.37-25.88,6.16,0,12.63,1.54,18.49,4.01Z"/><path d="M710.7,145.87h-22.19l3.08-35.13h24.34l8.63-39.75h38.83l-3.39,39.75h35.75l-3.08,35.13h-35.75l-5.85,66.87c-1.23,13.25,6.16,22.19,19.11,22.19,4.31,0,11.09-.92,16.33-2.16l-3.39,36.98c-9.55,3.08-22.19,4.93-32.05,4.93-31.43,0-49.61-23.73-46.53-57.32l6.16-71.49Z"/><path d="M818.55,209.35l13.63-151.64h46.22l-13.01,143.63c-1.54,19.11,8.32,32.66,26.5,32.66s34.2-14.48,36.05-34.51l7.7-88.75h46.22l-13.87,157.77h-44.99l1.85-21.26c-12.63,16.95-32.05,27.43-52.69,27.43-35.44,0-57.01-27.43-53.62-65.33Z"/><path d="M1048.13,339.39h-46.22l20.03-228.65h45.61l-1.85,19.11c13.87-15.72,33.28-25.27,55.16-25.27,43.76,0,71.8,35.13,67.18,85.05-4.31,49.92-38.21,85.05-82.28,85.05-21.57,0-38.83-9.24-49.92-25.27l-7.7,89.98ZM1104.52,146.18c-24.04,0-43.14,18.49-45.3,43.45s13.56,43.45,37.59,43.45,42.83-18.49,44.99-43.45c2.46-25.27-13.56-43.45-37.29-43.45Z"/><path class="e" d="M348.31,454.6c-11.4,48.38-60.09,83.2-116.17,83.2-67.79,0-112.78-49.3-106.93-117.41,5.85-68.1,59.47-117.41,127.27-117.41,55.47,0,97.99,35.75,101.38,85.36l-48.69,5.55c-4.01-27.12-26.81-46.53-55.16-46.53-39.14,0-69.33,30.2-73.03,73.03s21.26,73.03,60.09,73.03c27.73,0,54.54-19.11,63.48-44.99l47.76,6.16Z"/><path class="e" d="M512.55,372.33h46.22l-13.87,157.77h-46.22l1.85-21.88c-13.87,17.56-33.59,28.04-56.08,28.04-44.37,0-72.42-35.13-68.1-85.05,4.62-49.92,38.83-85.05,83.2-85.05,22.5,0,40.37,10.48,51.15,28.04l1.85-21.88ZM505.16,451.21c2.46-25.58-13.25-44.37-37.29-44.37s-42.83,18.8-45.3,44.37c-2.16,25.58,13.56,44.37,37.59,44.37s42.83-18.8,44.99-44.37Z"/><path class="e" d="M704.23,370.48l-3.39,40.98c-8.63-3.7-18.8-5.85-25.58-5.85-20.03,0-34.51,16.95-36.67,40.68l-7.4,83.82h-46.22l13.87-157.77h44.37l-1.85,20.03c10.79-15.72,26.81-25.88,44.37-25.88,6.16,0,12.63,1.54,18.49,4.01Z"/><path class="e" d="M857.07,301.45h46.22l-20.03,228.65h-45.61l1.54-19.11c-13.56,15.72-32.66,25.27-54.85,25.27-43.76,0-71.8-35.13-67.49-85.05,4.62-49.92,38.83-85.05,82.58-85.05,21.57,0,38.83,9.24,49.61,25.27l8.01-89.98ZM800.68,494.66c24.04,0,42.83-18.49,44.99-43.45,2.16-24.96-13.25-43.45-37.29-43.45s-43.14,18.49-45.3,43.45c-2.16,25.27,13.87,43.45,37.59,43.45Z"/><path class="e" d="M921.78,477.41h39.13c-1.23,15.72,12.33,26.81,32.36,26.81,16.95,0,30.2-8.01,31.12-18.8,2.46-31.74-101.69-.31-95.83-66.87,2.77-30.82,33.9-53,72.42-53,42.22,0,70.57,22.8,68.1,54.54h-40.68c.92-12.94-12.02-21.88-30.51-21.88-14.48,0-26.5,7.4-27.43,17.56-2.77,30.2,103.54,5.24,98.61,64.71-2.77,32.66-35.44,56.39-79.19,56.39s-71.18-24.96-68.1-59.47Z"/><polygon points="863.1 6.22 812.84 51.79 901.36 51.79 863.1 6.22"/></g></svg>`
    .replace('.e{fill:#059669;}', '.e{fill:#ffffff;}')
    .replace('<svg ', '<svg fill="#ffffff" ');
const STORY_LOGO_RATIO = 1193.52 / 546.68; // width : height of the wordmark

let storyLogoImg = null;
let storyLogoReady = false;

// Lazily decode the inlined wordmark for the share image. Preloaded when the Story
// tab renders so it's ready by the time the player clicks Share; if it hasn't
// decoded yet, buildStoryImageCanvas falls back to a text label.
function ensureStoryLogo() {
    if (storyLogoImg) return;
    storyLogoImg = new Image();
    storyLogoImg.onload = () => { storyLogoReady = true; };
    storyLogoImg.onerror = () => { storyLogoReady = false; }; // keep the text fallback
    storyLogoImg.src = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(STORY_LOGO_SVG);
}

// Draw the bare card (themed band, archetype, narrative, chips, CTA) onto a canvas
// sized to its content — 1080 wide, square corners. buildStoryImageCanvas() frames
// this on a gray backdrop for sharing. Text + an inlined data-URL logo only, so the
// canvas never taints and toDataURL/toBlob always succeed.
function buildStoryCardCanvas(story) {
    const W = 1080, PAD = 64, maxW = W - PAD * 2;
    const canvas = document.createElement('canvas');
    canvas.width = W;
    const ctx = canvas.getContext('2d');
    // Canvas fillText (unlike the DOM) won't fall back to the system color-emoji
    // font unless it's named explicitly, so the archetype emoji renders as tofu/
    // nothing without these trailing families.
    const font = (spec) => `${spec} -apple-system, "Segoe UI", Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", sans-serif`;
    const [c0, c1] = story.archetype.colors;

    const roundRect = (x, y, w, h, r) => {
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.arcTo(x + w, y, x + w, y + h, r);
        ctx.arcTo(x + w, y + h, x, y + h, r);
        ctx.arcTo(x, y + h, x, y, r);
        ctx.arcTo(x, y, x + w, y, r);
        ctx.closePath();
    };

    // ── Pass 1: word-wrap the narrative so we can size the card to its content
    // (a fixed height left a big gap under short stories). ──
    ctx.font = font('400 31px');
    const lineH = 46;
    const lines = [];
    let line = '';
    story.paragraph.split(' ').forEach(word => {
        const test = line ? line + ' ' + word : word;
        if (ctx.measureText(test).width > maxW && line) { lines.push(line); line = word; }
        else line = test;
    });
    if (line) lines.push(line);

    // ── Layout (baselines), derived from the wrapped line count ──
    const BAND_H = 320;
    const nameY = 432;
    const pStart = 502;
    const lastLineY = pStart + (lines.length - 1) * lineH;
    const chipH = 130;
    const chipY = lastLineY + 50;
    const ctaY = chipY + chipH + 66;     // "What kind of founder are you?"
    const urlY = ctaY + 44;              // play link
    const H = Math.round(urlY + 46);
    canvas.height = H; // NB: resets ctx state — every draw below re-sets its font/style

    // Card background + themed header band
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, W, H);
    const band = ctx.createLinearGradient(0, 0, W, BAND_H);
    band.addColorStop(0, c0);
    band.addColorStop(1, c1);
    ctx.fillStyle = band;
    ctx.fillRect(0, 0, W, BAND_H);

    // Brand wordmark (white logo), with a text label as the cold-start fallback.
    ctx.textBaseline = 'alphabetic';
    ensureStoryLogo();
    if (storyLogoReady && storyLogoImg.naturalWidth) {
        const logoH = 50;
        ctx.drawImage(storyLogoImg, PAD, 34, logoH * STORY_LOGO_RATIO, logoH);
    } else {
        ctx.fillStyle = 'rgba(255,255,255,0.85)';
        ctx.font = font('700 26px');
        ctx.fillText('⚡ STARTUP CARDS', PAD, 72);
    }

    // Archetype: emoji, name, blurb
    ctx.fillStyle = '#ffffff';
    ctx.font = font('400 96px');
    ctx.fillText(story.archetype.emoji, PAD, 225);
    ctx.font = font('800 56px');
    ctx.fillText(story.archetype.name, PAD + 130, 190);
    ctx.fillStyle = 'rgba(255,255,255,0.9)';
    ctx.font = font('400 28px');
    ctx.fillText(story.archetype.blurb, PAD + 130, 235);

    // Company name
    ctx.fillStyle = c1;
    ctx.font = font('800 60px');
    ctx.fillText(gameState.companyName || 'Our Startup', PAD, nameY);

    // Narrative paragraph
    ctx.fillStyle = '#1e293b';
    ctx.font = font('400 31px');
    lines.forEach((ln, i) => ctx.fillText(ln, PAD, pStart + i * lineH));

    // Stat chips
    const chips = [
        [formatCurrency(estimateValuation()), 'Valuation'],
        [gameState.customers.toLocaleString(), 'Customers'],
        [String(gameState.teamSize), 'Team'],
        [storyAgeShort(), 'Age']
    ];
    const gap = 20, chipW = (maxW - gap * 3) / 4;
    chips.forEach(([val, label], i) => {
        const x = PAD + i * (chipW + gap);
        ctx.fillStyle = '#f1f5f9';
        roundRect(x, chipY, chipW, chipH, 18);
        ctx.fill();
        ctx.textAlign = 'center';
        ctx.fillStyle = c0;
        let vf = 38;
        ctx.font = font('800 38px');
        while (ctx.measureText(val).width > chipW - 20 && vf > 22) {
            vf -= 2;
            ctx.font = font(`800 ${vf}px`);
        }
        ctx.fillText(val, x + chipW / 2, chipY + 62);
        ctx.fillStyle = '#64748b';
        ctx.font = font('600 22px');
        ctx.fillText(label, x + chipW / 2, chipY + 100);
        ctx.textAlign = 'left';
    });

    // Footer call-to-action
    ctx.textAlign = 'center';
    ctx.fillStyle = c1;
    ctx.font = font('800 34px');
    ctx.fillText('What kind of founder are you?', W / 2, ctaY);
    ctx.fillStyle = '#64748b';
    ctx.font = font('600 26px');
    ctx.fillText('Play free → dlightning.org/games', W / 2, urlY);
    ctx.textAlign = 'left';

    return canvas;
}

// Frame the bare card on a gray, 4:5-portrait backdrop (LinkedIn/Instagram-friendly)
// with rounded corners and a drop shadow — matching the live preview and giving the
// shared image breathing room instead of bleeding to the edges.
function buildStoryImageCanvas(story) {
    const card = buildStoryCardCanvas(story);
    const MARGIN = 64;   // gray frame around the card
    const RADIUS = 36;
    const OUTER_W = card.width + MARGIN * 2;
    // Target a 4:5 portrait, but grow if an unusually long story makes the card tall
    // (so we never crop) — typical stories land exactly on 4:5.
    const OUTER_H = Math.max(Math.round(OUTER_W * 5 / 4), card.height + MARGIN * 2);
    const cardX = MARGIN;
    const cardY = Math.round((OUTER_H - card.height) / 2);

    const out = document.createElement('canvas');
    out.width = OUTER_W;
    out.height = OUTER_H;
    const ctx = out.getContext('2d');

    const roundRect = (x, y, w, h, r) => {
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.arcTo(x + w, y, x + w, y + h, r);
        ctx.arcTo(x + w, y + h, x, y + h, r);
        ctx.arcTo(x, y + h, x, y, r);
        ctx.arcTo(x, y, x + w, y, r);
        ctx.closePath();
    };

    // Gray backdrop
    ctx.fillStyle = '#e7eaed';
    ctx.fillRect(0, 0, OUTER_W, OUTER_H);

    // Drop shadow, cast by a rounded white silhouette the card then fills
    ctx.save();
    ctx.shadowColor = 'rgba(15, 23, 42, 0.22)';
    ctx.shadowBlur = 48;
    ctx.shadowOffsetY = 18;
    ctx.fillStyle = '#ffffff';
    roundRect(cardX, cardY, card.width, card.height, RADIUS);
    ctx.fill();
    ctx.restore();

    // Clip to the rounded card and paint the bare card bitmap into it (rounds corners)
    ctx.save();
    roundRect(cardX, cardY, card.width, card.height, RADIUS);
    ctx.clip();
    ctx.drawImage(card, cardX, cardY);
    ctx.restore();

    return out;
}

// Build a fresh share canvas for the current state.
function getStoryCanvas() {
    const story = generateCompanyStory();
    return story ? buildStoryImageCanvas(story) : null;
}

// Synchronous data-URL -> Blob so navigator.share is still called inside the click's
// user-gesture window (an async toBlob can drop that activation in some browsers).
function dataURLtoBlob(dataURL) {
    const [head, b64] = dataURL.split(',');
    const mime = (head.match(/:(.*?);/) || [])[1] || 'image/png';
    const bin = atob(b64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return new Blob([arr], { type: mime });
}

function downloadStoryImage(canvas, filename, setHint) {
    const link = document.createElement('a');
    link.href = canvas.toDataURL('image/png');
    link.download = filename;
    link.click();
    if (setHint) setHint('Image saved — share it anywhere! 🖼️');
}

// Share the image card via the native share sheet (with the story text attached),
// falling back to a PNG download when file-sharing isn't supported.
function shareStoryImage() {
    const canvas = getStoryCanvas();
    if (!canvas) return;
    const story = generateCompanyStory();
    const hint = document.getElementById('companyStoryHint');
    const setHint = (msg) => { if (hint) hint.textContent = msg; };
    const filename = (gameState.companyName || 'startup').replace(/[^a-z0-9]+/gi, '_').toLowerCase() + '-startup-cards.png';

    let file = null;
    try {
        file = new File([dataURLtoBlob(canvas.toDataURL('image/png'))], filename, { type: 'image/png' });
    } catch (e) { /* fall back to download */ }

    if (file && navigator.canShare && navigator.canShare({ files: [file] })) {
        navigator.share({
            files: [file],
            title: gameState.companyName || 'My startup',
            text: story ? story.shareText : ''
        })
            .then(() => setHint('Shared! 🎉'))
            .catch(err => { if (!err || err.name !== 'AbortError') downloadStoryImage(canvas, filename, setHint); });
        return;
    }
    downloadStoryImage(canvas, filename, setHint);
}

// Render the Story tab: archetype headline (themed), the narrative pull-quote, a
// live preview of the shareable image card, and image/text share buttons. Falls
// back to an empty state prompting the player to make a few decisions first.
// ---- Post-mortem (end-of-run retrospective on the Story tab) ----
//
// When a run has ENDED — a failure (endings.js) or a winning exit (actions.js) —
// the Story tab gains a retrospective: a verdict block up top (renderPostMortemBlock)
// and a past-tense closing act in the narrative arc (see generateStoryArc). The
// verdict/exit cards link straight here via openPostMortem().

// How this run ended, or null if it's still going. Maps the failure endingKey and
// the exit flag onto a single outcome key shared by POST_MORTEM and the story close.
function getRunOutcome() {
    if (gameState.exited) return 'exit';
    if (gameState.gameOver && gameState.endingKey) return gameState.endingKey;
    return null;
}

// Verdict copy per outcome: a dramatic headline + a terse one-line summary. `tone`
// drives the block's colour (down = somber, up = celebratory).
const POST_MORTEM = {
    insolvency: { tone: 'down', kicker: 'Post-mortem', headline: '…and the money ran out.',
        verdict: () => 'Burned the last dollar with the bills still coming in.' },
    ideaFlop:   { tone: 'down', kicker: 'Post-mortem', headline: '…and we finally called it.',
        verdict: () => 'Built for years; the customers we needed never came.' },
    burnout:    { tone: 'down', kicker: 'Post-mortem', headline: '…and the founder stepped away.',
        verdict: () => 'Ran on empty too long — and chose, bravely, to recover.' },
    exit:       { tone: 'up',   kicker: 'The exit',    headline: '…and then we sold.',
        verdict: (gs) => `Acquired for ${formatCurrency(gs.exitSalePrice || 0)} — we built something worth buying.` }
};

// Headline numbers for the verdict block: how far the run got before it ended.
function buildPostMortemStats() {
    const months = Math.max(0, Math.round(gameState.currentMonth - 1));
    let survived;
    if (months < 12) {
        survived = `${months} month${months === 1 ? '' : 's'}`;
    } else {
        const y = Math.floor(months / 12), m = months % 12;
        survived = m ? `${y}y ${m}mo` : `${y} year${y === 1 ? '' : 's'}`;
    }
    const series = (typeof getCompanyMonthlySeries === 'function') ? getCompanyMonthlySeries() : [];
    const peakCustomers = Math.max(gameState.customers || 0, ...series.map(s => s.customers || 0));
    const peakRevenue = Math.max(gameState.monthlyRevenue || 0, ...series.map(s => s.monthlyRevenue || 0));
    return {
        survived,
        peakCustomers,
        peakRevenue,
        lifetimeRevenue: Math.max(0, Math.round(gameState.totalRevenue || 0)),
        decisions: (gameState.selectedCards || []).length
    };
}

// ---- Post-mortem cause analysis ----
// The verdict block above just restates headline numbers (which the player can
// already read elsewhere). THIS is the part that isn't surfaced anywhere else: a
// short diagnosis of WHY the run ended the way it did, read straight out of the
// decision log (gameState.selectedCards). Each ending has a different fatal metric,
// so each reads the same log through a different lens:
//   • burnout    → which decisions piled the most founder stress on
//   • insolvency → the monthly burn-vs-revenue gap + the heaviest one-time spends
//   • ideaFlop   → where the effort went while customers never showed
//   • exit       → (celebratory) the moves that built something worth buying
// Decisions repeated across the run (e.g. two "Proprietary Hardware" builds) are
// grouped by title so a recurring culprit reads as one line ("×2").

// Group cards by title and sum one metric, keeping only same-signed contributions
// (keepSign +1 = the metric pushed UP, -1 = pushed DOWN). Returns rows sorted by
// magnitude, biggest first — so the top of the list is the biggest driver.
function sumImpactByTitle(cards, metric, keepSign) {
    const map = new Map();
    (cards || []).forEach(c => {
        const v = (c.impact && c.impact[metric]) || 0;
        if (keepSign > 0 ? v > 0 : v < 0) {
            const e = map.get(c.title) || { title: c.title, total: 0, count: 0 };
            e.total += v;
            e.count += 1;
            map.set(c.title, e);
        }
    });
    return Array.from(map.values())
        .sort((a, b) => keepSign > 0 ? b.total - a.total : a.total - b.total);
}

// Build the "what led here" diagnosis for an ended run, or null when there's not
// enough in the log to say anything useful. { lead, drivers:[{label,value}], note }.
function buildPostMortemCause(outcome) {
    const cards = gameState.selectedCards || [];
    const driverLabel = (r) => r.count > 1 ? `${r.title} ×${r.count}` : r.title;

    if (outcome === 'burnout') {
        const adders = sumImpactByTitle(cards, 'stress', +1);
        const relievers = sumImpactByTitle(cards, 'stress', -1);
        if (!adders.length) return null;
        const addedCount = adders.reduce((n, r) => n + r.count, 0);
        const easedCount = relievers.reduce((n, r) => n + r.count, 0);
        const lead = `Founder stress only ever climbed. ${addedCount} decision${addedCount === 1 ? '' : 's'} `
            + `piled on pressure against just ${easedCount} that eased it — and these weighed heaviest:`;
        return {
            lead,
            drivers: adders.slice(0, 3).map(r => ({ label: driverLabel(r), value: `+${Math.round(r.total)} stress` })),
            note: 'Stress never decays on its own — only a deliberate breather brings it down. It sat pinned at the max long enough that the founder, not the business, gave out.'
        };
    }

    if (outcome === 'insolvency') {
        const costs = sumImpactByTitle(cards, 'cost', +1);
        const gap = Math.round((gameState.monthlyBurn || 0) - (gameState.monthlyRevenue || 0));
        const lead = gap > 0
            ? `The burn outran the revenue. By the end you were spending ${formatCurrency(Math.round(gameState.monthlyBurn || 0))} a month `
              + `against ${formatCurrency(Math.round(gameState.monthlyRevenue || 0))} coming in — losing ${formatCurrency(gap)} every month with no cash left to absorb it.`
            : `The cash ran out before the revenue could catch up.`;
        if (!costs.length) return { lead, drivers: [], note: '' };
        return {
            lead: lead + ` The heaviest one-time spends along the way:`,
            drivers: costs.slice(0, 3).map(r => ({ label: driverLabel(r), value: `−${formatCurrency(Math.round(r.total))}` })),
            note: ''
        };
    }

    if (outcome === 'ideaFlop') {
        const count = (cat) => cards.filter(c => c.category === cat).length;
        const marketing = count('marketing');
        const validation = count('validation');
        const product = count('product');
        const lead = `Years in, the market never answered. The product got built — ${product} product `
            + `decision${product === 1 ? '' : 's'} — but only ${marketing} marketing push${marketing === 1 ? '' : 'es'} `
            + `to get the word out, and ${validation} time${validation === 1 ? '' : 's'} asking customers what they actually wanted.`;
        return {
            lead,
            drivers: [
                { label: 'Marketing pushes', value: String(marketing) },
                { label: 'Customer validation', value: String(validation) },
                { label: 'Product builds', value: String(product) }
            ],
            note: 'Building was never the problem. Being found — and building the right thing — was.'
        };
    }

    if (outcome === 'exit') {
        const growth = sumImpactByTitle(cards, 'growth', +1);
        if (!growth.length) return null;
        return {
            lead: `You built something worth buying. The moves that drove the most growth along the way:`,
            drivers: growth.slice(0, 3).map(r => ({ label: driverLabel(r), value: `+${Math.round(r.total)} growth` })),
            note: ''
        };
    }

    return null;
}

// Render the cause block (or '' when there's nothing to diagnose).
function renderPostMortemCause(outcome) {
    const cause = buildPostMortemCause(outcome);
    if (!cause) return '';
    const drivers = (cause.drivers || []).map(d =>
        `<li><span class="pm-driver-label">${d.label}</span><span class="pm-driver-val">${d.value}</span></li>`).join('');
    return `
        <div class="pm-cause">
            <div class="pm-cause-title">What led here</div>
            <p class="pm-cause-lead">${cause.lead}</p>
            ${drivers ? `<ul class="pm-drivers">${drivers}</ul>` : ''}
            ${cause.note ? `<p class="pm-note">${cause.note}</p>` : ''}
        </div>`;
}

// The verdict block shown at the top of the Story tab for an ended run (or '' when
// the run is still live, so the Story tab renders unchanged mid-game).
function renderPostMortemBlock() {
    const outcome = getRunOutcome();
    const pm = outcome && POST_MORTEM[outcome];
    if (!pm) return '';
    const s = buildPostMortemStats();
    const peakLine = `${Math.round(s.peakCustomers).toLocaleString()} · ${formatCurrency(s.peakRevenue)}/mo`;
    return `
        <div class="story-postmortem ${pm.tone}">
            <div class="pm-kicker">${pm.kicker}</div>
            <div class="pm-headline">${pm.headline}</div>
            <ul class="pm-stats">
                <li><span>Lasted</span><strong>${s.survived}</strong></li>
                <li><span>Peak</span><strong>${peakLine}</strong></li>
                <li><span>Lifetime revenue</span><strong>${formatCurrency(s.lifetimeRevenue)}</strong></li>
                <li><span>Decisions</span><strong>${s.decisions}</strong></li>
            </ul>
            <blockquote class="pm-verdict">${pm.verdict(gameState)}</blockquote>
            ${renderPostMortemCause(outcome)}
        </div>`;
}

// Open the company modal straight to the Story tab — the "Read the post-mortem"
// entry point from the verdict (endings.js) and exit (actions.js) cards.
function openPostMortem() {
    if (typeof showCompanyMetricsModal === 'function') showCompanyMetricsModal();
    if (typeof switchCompanyTab === 'function') switchCompanyTab('story');
}

function populateCompanyStory() {
    const body = document.getElementById('companyStoryBody');
    if (!body) return;

    const story = generateCompanyStory();
    if (!story) {
        body.innerHTML = `
            <div class="story-empty">
                <div class="story-empty-icon">📖</div>
                <h3>Your story starts with a decision</h3>
                <p>Add a few cards and your company's story will write itself here — ready to share.</p>
            </div>`;
        return;
    }

    // Preload the brand logo now so the share image (rasterized on click) has it ready.
    ensureStoryLogo();

    const a = story.archetype;
    const [c0, c1] = a.colors;
    const chips = [
        [formatCurrency(estimateValuation()), 'Valuation'],
        [gameState.customers.toLocaleString(), 'Customers'],
        [String(gameState.teamSize), 'Team'],
        [storyAgeShort(), 'Age']
    ];
    const chipsHTML = chips.map(([v, l]) =>
        `<div class="story-card-chip"><span class="v">${v}</span><span class="l">${l}</span></div>`).join('');

    // The story that goes *below* the image — the first-person prose a player pastes
    // alongside the card in a social post. Rendered as flowing paragraphs (acts).
    const arcHTML = (story.arc || []).map(p => `<p class="story-arc-para">${p}</p>`).join('');

    // The .story-card is a live HTML replica of the share image — same logo, themed
    // band, archetype, narrative, chips, and CTA. The PNG is only built on share, so
    // there's no per-turn canvas raster while the panel is pinned open.
    body.innerHTML = `
        <div class="company-story">
            ${renderPostMortemBlock()}
            <div class="story-image-caption">Your shareable card</div>
            <div class="story-card" style="--c0:${c0};--c1:${c1}">
                <div class="story-card-band">
                    <img class="story-card-logo" src="svg/startupCards.svg" alt="Startup Cards" />
                    <div class="story-card-arch">
                        <span class="story-card-emoji" aria-hidden="true">${a.emoji}</span>
                        <div>
                            <div class="story-card-arch-name">${a.name}</div>
                            <div class="story-card-arch-blurb">${a.blurb}</div>
                        </div>
                    </div>
                </div>
                <div class="story-card-body">
                    <div class="story-card-company">${gameState.companyName || 'Our Startup'}</div>
                    <p class="story-card-narrative">${story.paragraph}</p>
                    <div class="story-card-chips">${chipsHTML}</div>
                    <div class="story-card-cta">What kind of founder are you?</div>
                    <div class="story-card-url">Play free → dlightning.org/games</div>
                </div>
            </div>
            <div class="story-arc">
                <div class="story-arc-title">Your shareable story</div>
                <p class="story-arc-sub">The tale to post with your card — it grows richer the longer you build.</p>
                <div class="story-arc-prose">${arcHTML}</div>
            </div>
            <div class="company-story-actions">
                <button type="button" class="btn-share" onclick="shareStoryImage()">📣 Share image</button>
                <button type="button" class="btn-share btn-share-secondary" onclick="shareCompanyStory()">🔗 Copy text</button>
            </div>
            <p class="company-story-hint" id="companyStoryHint" role="status" aria-live="polite"></p>
        </div>`;
}

// Copy the story text to the clipboard, falling back to a selectable dialog where
// the clipboard API isn't available (e.g. file:// or older browsers).
async function shareCompanyStory() {
    const story = generateCompanyStory();
    if (!story) return;
    const hint = document.getElementById('companyStoryHint');
    const setHint = (msg) => { if (hint) hint.textContent = msg; };

    // The image button owns the native share sheet; this "Copy text" path goes
    // straight to the clipboard, with a selectable dialog as the last resort.
    if (navigator.clipboard && navigator.clipboard.writeText) {
        try {
            await navigator.clipboard.writeText(story.shareText);
            setHint('Copied to clipboard — paste it anywhere! 📋');
            return;
        } catch (err) { /* fall through to the manual dialog */ }
    }

    showAlertDialog({
        icon: '📣',
        title: 'Copy your story',
        message: story.shareText.replace(/\n/g, '<br>')
    });
}

// Switch between the Metrics, Org Chart, and Story panes inside the company modal.
function switchCompanyTab(tab) {
    const panes = {
        metrics: document.getElementById('companyMetricsBody'),
        org: document.getElementById('companyOrgBody'),
        story: document.getElementById('companyStoryBody')
    };
    const tabs = {
        metrics: document.getElementById('companyTabMetrics'),
        org: document.getElementById('companyTabOrg'),
        story: document.getElementById('companyTabStory')
    };
    if (!panes.metrics || !panes.org) return;

    Object.keys(panes).forEach(key => {
        const pane = panes[key];
        const tabBtn = tabs[key];
        const active = key === tab;
        if (pane) {
            pane.hidden = !active;
            pane.classList.toggle('active', active);
        }
        if (tabBtn) {
            tabBtn.classList.toggle('active', active);
            tabBtn.setAttribute('aria-selected', String(active));
        }
    });

    // Build the pane's content lazily, on demand, when its tab is shown.
    if (tab === 'org') populateOrgChart();
    else if (tab === 'story') populateCompanyStory();
}

// Persist the player's CEO name as they type (used elsewhere later).
function updateCeoName(value) {
    gameState.ceoName = value;
}

// Build up-to-two-letter initials from a person's name for the avatar circle.
function orgInitials(name) {
    const parts = (name || '').trim().split(/\s+/).filter(Boolean);
    if (!parts.length) return '?';
    const letters = parts.length === 1
        ? parts[0].slice(0, 2)
        : parts[0][0] + parts[parts.length - 1][0];
    return letters.toUpperCase();
}

// Render the org chart: the player as CEO up top, then hired employees laid out
// in seniority tiers (Senior above Mid above Junior). Re-rendered each time the
// Org Chart tab is opened so newly hired slots appear.
function populateOrgChart() {
    const body = document.getElementById('companyOrgBody');
    if (!body) return;

    const employees = gameState.employees || [];
    const byLevel = { Senior: [], Mid: [], Junior: [] };
    const coFounders = [];
    // Tag each employee with its index in gameState.employees so the action buttons
    // act on the right person regardless of tier sorting. Co-founders are pulled out
    // and shown up top alongside the CEO instead of in the seniority tiers.
    employees.forEach((e, i) => {
        if (e.coFounder) { coFounders.push({ emp: e, idx: i }); return; }
        (byLevel[e.level] || byLevel.Mid).push({ emp: e, idx: i });
    });
    // Within a tier, group the same roles together (e.g. all Sr. PMs side by side).
    Object.values(byLevel).forEach(arr => arr.sort((a, b) => a.emp.role.localeCompare(b.emp.role)));

    const hasCoFounder = coFounders.length > 0;
    const tiers = [
        ['Senior', 'Senior'],
        ['Mid', 'Mid-Level'],
        ['Junior', 'Junior']
    ];

    const nodeHTML = ({ emp: e, idx }) => {
        const tenure = formatTenure(employeeYearsOfService(e));
        const safeName = (e.name || '').replace(/"/g, '&quot;');
        // Right-side action: promote for Junior/Mid; "make co-founder" for a Senior
        // when no co-founder exists yet; otherwise a spacer to keep the avatar centered.
        let rightAction;
        if (e.level !== 'Senior') {
            rightAction = `<button type="button" class="org-action org-promote" onclick="promoteEmployee(${idx})"
                title="Promote ${safeName}" aria-label="Promote ${safeName}">▲</button>`;
        } else if (!hasCoFounder) {
            rightAction = `<button type="button" class="org-action org-cofound" onclick="makeCoFounder(${idx})"
                title="Make ${safeName} a co-founder" aria-label="Make ${safeName} a co-founder">★</button>`;
        } else {
            rightAction = `<span class="org-action org-action-spacer" aria-hidden="true"></span>`;
        }
        return `
        <div class="org-node org-level-${e.level.toLowerCase()}">
            <div class="org-node-top">
                <button type="button" class="org-action org-fire" onclick="fireEmployee(${idx})"
                    title="Lay off ${safeName}" aria-label="Lay off ${safeName}">✕</button>
                <div class="org-avatar org-avatar-initials">${orgInitials(e.name)}</div>
                ${rightAction}
            </div>
            <div class="org-name">${e.name || e.role}</div>
            <div class="org-title">${e.role}</div>
            <div class="org-meta">
                <span class="org-badge org-badge-${e.level.toLowerCase()}">${e.level}</span>
                <span class="org-salary">$${Math.round(e.salary / 1000)}k</span>
            </div>
            <div class="org-tenure">${tenure} of service</div>
        </div>
    `;
    };

    const coFounderNodeHTML = ({ emp: e }) => `
        <div class="org-node org-ceo org-cofounder">
            <div class="org-ceo-label">CO-FOUNDER</div>
            <div class="org-cofounder-name">${e.name || e.role}</div>
            <div class="org-role">${e.role} · ${e.equity || 0}% equity</div>
        </div>
    `;

    const tierRows = tiers
        .filter(([key]) => byLevel[key].length)
        .map(([key, label]) => `
            <div class="org-tier">
                <div class="org-tier-label">${label}</div>
                <div class="org-row">${byLevel[key].map(nodeHTML).join('')}</div>
            </div>
        `).join('');

    const ceoName = (gameState.ceoName || '');
    const tieredCount = employees.length - coFounders.length;
    const founders = 1 + coFounders.length;

    body.innerHTML = `
        <div class="org-chart">
            <div class="org-row org-ceo-row">
                <div class="org-node org-ceo">
                    <div class="org-ceo-label">CEO</div>
                    <input type="text" class="org-ceo-name" id="orgCeoName"
                        placeholder="Your name" value="${ceoName.replace(/"/g, '&quot;')}"
                        oninput="updateCeoName(this.value)" aria-label="Your name (CEO)" />
                    <div class="org-role">Chief Executive Officer · Founder</div>
                </div>
                ${coFounders.map(coFounderNodeHTML).join('')}
            </div>
            ${tieredCount ? '<div class="org-trunk"></div>' : ''}
            <div class="org-tiers">
                ${tierRows}
            </div>
            ${employees.length
                ? `<div class="org-footnote">${tieredCount} employee${tieredCount === 1 ? '' : 's'} · ${founders} founder${founders === 1 ? '' : 's'}</div>`
                : '<div class="org-empty">No employees yet. Hire team members to grow your org chart.</div>'}
        </div>
    `;
}

// Render a month count as "yr mo" with fractional months, e.g. 63.4 -> "5yr 3.4mo".
// Under a year it drops the "yr" part (e.g. "3.4mo"). Used for the runway readout.
// "mo" rather than "M" so months aren't misread as millions next to the cash figures.
function formatMonthsDuration(totalMonths) {
    totalMonths = Math.max(0, totalMonths);
    const years = Math.floor(totalMonths / 12);
    const months = totalMonths - years * 12;
    return years > 0 ? `${years}yr ${months.toFixed(1)}mo` : `${months.toFixed(1)}mo`;
}

function formatCurrency(amount) {
    const absAmount = Math.abs(amount);
    const isNegative = amount < 0;
    const prefix = isNegative ? '-$' : '$';
    
    if (absAmount >= 1000000) {
        return prefix + (absAmount / 1000000).toFixed(1) + 'M';
    } else if (absAmount >= 1000) {
        return prefix + (absAmount / 1000).toFixed(1) + 'K';
    } else {
        return prefix + absAmount.toFixed(0);
    }
}

function exportCompanyReport() {
    const reportData = {
        companyName: document.getElementById('companyName').textContent,
        reportDate: new Date().toISOString(),
        // Elapsed time since founding (founding = month 1 = 0 elapsed), matching
        // companyAgePhrase's convention. currentYear is an ordinal (1 all through year
        // one), so it can't be used as a count of elapsed years.
        timeInBusiness: (() => {
            const months = Math.max(0, gameState.currentMonth - 1);
            const yrs = Math.floor(months / 12);
            const mos = Math.round((months - yrs * 12) * 10) / 10;
            return yrs > 0 ? `${yrs} year${yrs === 1 ? '' : 's'}, ${mos} months` : `${mos} months`;
        })(),
        
        // Financial metrics
        financial: {
            totalRevenue: gameState.totalRevenue,
            monthlyRevenue: gameState.monthlyRevenue,
            monthlyBurn: gameState.monthlyBurn,
            netIncome: gameState.monthlyRevenue - gameState.monthlyBurn,
            currentRunway: gameState.runway,
            runwayMonths: gameState.runway > 0 ? Math.floor(gameState.runway / Math.max(gameState.monthlyBurn - gameState.monthlyRevenue, 1)) : 0
        },
        
        // Customer metrics
        customer: {
            totalCustomers: gameState.customers,
            averageRevenuePerCustomer: gameState.customers > 0 ? (gameState.monthlyRevenue / gameState.customers) : 0,
            engagement: gameState.engagement,
            growth: gameState.growth
        },
        
        // Business metrics
        business: {
            teamSize: gameState.teamSize,
            confidence: gameState.confidence,
            credibility: gameState.credibility,
            reach: gameState.reach,
            founderStress: gameState.stress,
            founderWellbeing: getStressLevel(gameState.stress).label,
            decisionsCount: gameState.selectedCards.filter(card => card.category !== 'outcome').length,
            decisionRate: gameState.cardsGenerated > 0 ? (gameState.selectedCards.filter(card => card.category !== 'outcome').length / gameState.cardsGenerated) * 100 : 0
        },
        
        // Full selections for context
        businessDecisions: gameState.selectedCards,
        
        // Generated at
        exportedAt: new Date().toISOString()
    };
    
    const dataStr = JSON.stringify(reportData, null, 2);
    const dataBlob = new Blob([dataStr], {type: 'application/json'});
    
    const link = document.createElement('a');
    link.href = URL.createObjectURL(dataBlob);
    link.download = `${reportData.companyName.replace(/\s+/g, '_')}_company_metrics_report.json`;
    link.click();
    
    // Also log to console for debugging
    console.log('Company Metrics Report:', reportData);
    
    // Show a brief success message
    const originalText = event.target.textContent;
    event.target.textContent = 'Exported! ✓';
    event.target.style.background = '#10b981';
    
    setTimeout(() => {
        event.target.textContent = originalText;
        event.target.style.background = '';
    }, 2000);
}

// Initialize company metrics modal functionality
function initializeCompanyMetricsModal() {
    const companyNameDiv = document.getElementById('companyName');
    
    if (companyNameDiv) {
        // Make it look clickable
        companyNameDiv.style.cursor = 'pointer';
        companyNameDiv.style.transition = 'all 0.2s ease';
        
        // Add hover effect
        companyNameDiv.addEventListener('mouseenter', function() {
            this.style.transform = 'scale(1.05)';
            this.style.boxShadow = '0 4px 12px rgba(30, 58, 138, 0.3)';
        });
        
        companyNameDiv.addEventListener('mouseleave', function() {
            this.style.transform = 'scale(1)';
            this.style.boxShadow = '';
        });
        
        // Add click event (toggle: opens, or closes if already open)
        companyNameDiv.addEventListener('click', toggleCompanyMetricsModal);
    }
    
    // Modal event listeners for clicking outside to close
    document.addEventListener('click', (e) => {
        const modal = document.getElementById('companyMetricsModal');
        if (modal && e.target === modal) {
            closeCompanyMetricsModal();
        }
    });
    
    // Escape key to close modal
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            closeCompanyMetricsModal();
        }
    });
}
