    'Videographer':              [{ category: 'marketing', speed: 0.25 }],
    'Sales Manager':             [{ category: 'revenue', speed: 0.40 }, { category: 'business', speed: 0.15 }],
    'Customer Success Manager':  [{ category: 'validation', speed: 0.20 }, { category: 'product', speed: 0.10 }, { category: 'revenue', speed: 0.12 }], // also speeds revenue (expansion/upsell/renewals)
    'General Counsel':           [{ category: 'business', speed: 0.30 }, { category: 'esg', speed: 0.25 }]
