    // Is there already a co-founder? Only one Senior member can be elevated.
    function coFounderExists() {
        return (gameState.employees || []).some(e => e.coFounder);
    }

    // Elevate a Senior employee to co-founder (org-chart button). Opens a dialog to
    // choose how much equity to grant; the grant scales their cash-for-equity pay cut
    // and a leadership bonus (credibility/confidence up, founder stress down). One max.
    function makeCoFounder(idx) {
        const emp = gameState.employees[idx];
        if (!emp) return;
        if (emp.level !== 'Senior' || emp.coFounder) return;
        if (coFounderExists()) return;

        const baseSalary = emp.salary;
        // Effects derived from the equity % granted, so the live preview can show them.
        const effectsFor = (equity) => {
            const cut = Math.min(0.6, equity / 100); // trades cash for ownership
            return {
                equity,
                newSalary: Math.round(baseSalary * (1 - cut) / 1000) * 1000,
                credibility: Math.round(equity * 0.5),
                confidence: Math.round(equity * 0.3),
                stress: Math.round(equity * 0.6)
            };
        };

        showConfirmDialog({
            tone: 'founder',
            icon: '★',
            title: `Make ${emp.name} a co-founder?`,
            input: { label: 'Equity to grant', min: 1, max: 49, step: 1, value: 10, suffix: '%' },
            computeRows: (equity) => {
                const fx = effectsFor(equity);
                return [
                    ['Role', `Co-Founder · ${emp.role}`],
                    ['Your stake after', `${100 - equity}%`],
                    ['Salary', `${formatCurrency(baseSalary)} → ${formatCurrency(fx.newSalary)}/yr`],
                    ['Leadership', `+${fx.credibility} cred · +${fx.confidence} conf · −${fx.stress} stress`]
                ];
            },
            note: 'Co-founders trade salary for equity. You can only appoint one.',
            cancelLabel: 'Cancel',
            confirmLabel: 'Appoint co-founder',
            onConfirm: (equity) => {
                const fx = effectsFor(equity);
                emp.coFounder = true;
                emp.equity = equity;
                emp.title = 'Co-Founder';
                emp.salary = fx.newSalary;
                gameState.credibility += fx.credibility;
                gameState.confidence += fx.confidence;
                gameState.stress -= fx.stress;
                if (emp.card) {
                    emp.card._coFounderBonus = {
                        credibility: fx.credibility,
                        confidence: fx.confidence,
                        stress: fx.stress
                    };
                }
                recalcMonthlyBurn();
                clampMetrics();
                afterTeamChange();
            }
        });
    }

