    // then CACHED on the card (card._roll). A later timeline rebuild (after a selection
    // is removed) re-applies the exact same roll instead of re-rolling — a rebuild must
    // reproduce the run, not reshuffle it. randInt(lo, hi) is inclusive on both ends and
    // reproduces the original `Math.floor(Math.random() * span) + lo` ranges exactly.
    function randInt(lo, hi) { return Math.floor(Math.random() * (hi - lo + 1)) + lo; }
    function rollCategoryBonus(category) {
        switch (category) {
            case 'validation': return { confidence: randInt(5, 9) };
            case 'team':       return { credibility: randInt(4, 11), growth: randInt(2, 7) };
            case 'product':    return { engagement: randInt(8, 12) };
            case 'marketing':  return { reach: randInt(15, 34), growth: randInt(8, 19) };
            case 'business':   return { confidence: randInt(6, 17), credibility: randInt(5, 14) };
            case 'revenue':    return { confidence: randInt(10, 24) };
            case 'esg':        return { credibility: randInt(4, 9) };
            default:           return {};
        }
    }
    // Apply (sign +1) or reverse (sign -1) a card's category bonus, rolling + caching it
    // on first use. For team hires the roll is also mirrored into card._teamBonus, which
    // detachEmployee() reverses on layoff (kept for backward compatibility).
    function applyCategoryRoll(card, sign = 1) {
        if (!card._roll) {
            // Old saves predate _roll: a team card still carries its real rolled bonus in
            // _teamBonus, so reuse that to stay faithful; other categories re-roll once.
            if (card.category === 'team' && card._teamBonus) {
                card._roll = { credibility: card._teamBonus.credibility, growth: card._teamBonus.growth };
            } else {
                card._roll = rollCategoryBonus(card.category);
            }
        }
        const roll = card._roll;
        for (const k in roll) gameState[k] += sign * roll[k];
        if (card.category === 'team') {
            card._teamBonus = { credibility: roll.credibility || 0, growth: roll.growth || 0 };
        }
    }

    // Keep the percentage metrics in [0, 100] and counts non-negative after an
