            gameState.confidence  = Math.max(0, gameState.confidence  * (1 - CONFIDENCE_DECAY * dt));
            gameState.credibility = Math.max(0, gameState.credibility * (1 - CREDIBILITY_DECAY * dt));
            // Market climate drifts back toward normal — downturns and wars are weathered,
            // not permanent. Competitor pressure fades on its own, faster when you're
