        // would need to re-simulate the timeline. Today this only runs at init with no cards.
        gameState.growth = 0;
        gameState.engagement = 0;
        gameState.confidence = 0;
        gameState.credibility = 0;
        gameState.reach = 0;
        gameState.stress = 0;

