        if (gameState.selectedCards.length > 24 && gameState.monthlyRevenue > 4000 &&
            !hasLegalCover && gameState.fineFired && !gameState.fineRepeatFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "regulatory_fine_repeat");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.fineRepeatFired = true;
            }
        }

        // Third strike: ignored two fines and still no legal cover => the regulator
        // stops fining and takes you to court — a near-fatal blow (fires once)
        if (gameState.selectedCards.length > 36 && gameState.monthlyRevenue > 4000 &&
            !hasLegalCover && gameState.fineRepeatFired && !gameState.prosecutionFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "regulatory_prosecution");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.prosecutionFired = true;
            }
        }

        // Success makes you a target: strong growth + visibility => a bigger rival sues
