    // Warm the network cache for the upcoming card's SVG, without painting
    // anything visible — so a cached SVG can later appear instantly with its
    // intro animation intact, rather than always flashing a placeholder.
    function warmImageCache(card) {
        const img = card.querySelector('img[data-src]:not([data-precached]):not([data-loaded])');
        if (img && img.dataset.src) {
            new Image().src = img.dataset.src; // pre-fetch real SVG into cache
            img.dataset.precached = 'true';
        }
    }

    function loadImageForCard(card) {
        const slot = card.querySelector('img[data-src]:not([data-loaded])');
        if (!slot || !slot.dataset.src) return;

        // Mark handled immediately so repeat calls from updateStackClasses
        // don't insert a second image.
        slot.dataset.loaded = 'true';

        const container = slot.parentNode;
        const realSrc = slot.dataset.src;

        // Fresh element guarantees the SVG's intro animation plays from frame 0.
        // No placeholder: SVGs are tiny (<100kb) and load fast even on slow
        // connections, so we just show the real image the moment it's ready and
        // never flash a placeholder. The empty slot holds the card's fixed
        // height until the real image is in.
        const real = document.createElement('img');
        real.className = slot.className;
        real.alt = '';
        real.dataset.loaded = 'true';
        real.style.opacity = '0';
        container.insertBefore(real, slot);

        real.addEventListener('load', function () {
            real.style.opacity = '1';
            slot.remove();
        }, { once: true });

        real.src = realSrc; // instant if cached → load fires almost immediately
    }

