const SAVE_INDEX_KEY = 'startupSim:index';     // lightweight list of saves, for the picker
const SAVE_GAME_PREFIX = 'startupSim:game:';   // SAVE_GAME_PREFIX + id → full serialized state
const SAVE_VERSION = 1;

// Id of the game currently in play, assigned lazily the first time there's a
// decision worth saving. Null until then (and after a save is deleted).
let currentGameId = null;

// Sentinel for JSON, which can't represent Infinity (a stream paying out forever
// stores monthsRemaining: Infinity). Round-tripped via the reviver/replacer below.
const INFINITY_SENTINEL = '__Infinity__';

function storageAvailable() {
    try {
        const k = '__ss_test__';
        localStorage.setItem(k, '1');
        localStorage.removeItem(k);
        return true;
    } catch (e) {
        return false;
    }
}

function genGameId() {
    return 'g_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);
}

// ── (de)serialization ────────────────────────────────────────────────────────
// gameState is JSON-friendly except for three things, all handled here:
//  • Date fields (founded, each selected card's selectedAtDate) — Date.toJSON
//    already emits ISO strings on save; we revive them to Date objects on load.
//  • Infinity stream lifetimes — swapped for a sentinel via the replacer/reviver.
//  • employee.card — a live reference into selectedCards (promotions/layoffs
//    re-scale it in place). We store its index instead and re-link on load so
//    the restored employee points at the SAME card object, not a duplicate.

function serializeGameState() {
    const cards = gameState.selectedCards || [];
    const out = JSON.parse(JSON.stringify(gameState, (key, value) =>
        value === Infinity ? INFINITY_SENTINEL : value
    ));
    out.employees = (gameState.employees || []).map(e => {
        const copy = Object.assign({}, e);
        delete copy.card;
        copy.cardIndex = e.card ? cards.indexOf(e.card) : -1;
        return copy;
    });
    return out;
}

function deserializeGameState(raw) {
    const gs = raw;
    if (gs.founded) gs.founded = new Date(gs.founded);
    // Market state postdates early saves — default to a neutral market so restored runs
    // don't divide acquisition by an undefined climate (see advanceCustomers / engine tick).
    if (typeof gs.marketClimate !== 'number') gs.marketClimate = 1;
    if (typeof gs.competitorPressure !== 'number') gs.competitorPressure = 0;
    (gs.selectedCards || []).forEach(c => {
        if (c.selectedAtDate) c.selectedAtDate = new Date(c.selectedAtDate);
    });
    (gs.employees || []).forEach(e => {
        const idx = (typeof e.cardIndex === 'number') ? e.cardIndex : -1;
        e.card = idx >= 0 ? gs.selectedCards[idx] : null;
        delete e.cardIndex;
    });
    return gs;
}

// Mutate the live gameState object in place rather than reassigning it, so every
// module that closed over the original reference keeps seeing the restored state.
function replaceGameState(obj) {
    Object.keys(gameState).forEach(k => delete gameState[k]);
    Object.assign(gameState, obj);
}

// ── save index (the picker's source of truth) ────────────────────────────────

function readIndex() {
    try {
        const str = localStorage.getItem(SAVE_INDEX_KEY);
        const arr = str ? JSON.parse(str) : [];
        return Array.isArray(arr) ? arr : [];
    } catch (e) {
        return [];
    }
}

function writeIndex(arr) {
    try {
        localStorage.setItem(SAVE_INDEX_KEY, JSON.stringify(arr));
    } catch (e) { /* quota or unavailable — game still runs in memory */ }
}

// Compact, display-ready summary stored in the index so the picker doesn't have
// to parse every full save blob just to render the list.
function buildSaveSummary(id) {
    return {
        id,
        companyName: gameState.companyName,
        founded: gameState.founded instanceof Date ? gameState.founded.toISOString() : gameState.founded,
        savedAt: new Date().toISOString(),
        currentMonth: gameState.currentMonth,
        currentYear: gameState.currentYear,
        runway: Math.round(gameState.runway),
        monthlyRevenue: Math.round(gameState.monthlyRevenue),
        teamSize: gameState.teamSize,
        customers: gameState.customers,
        decisions: (gameState.selectedCards || []).length,
        exited: !!gameState.exited,
        exitSalePrice: Math.round(gameState.exitSalePrice || 0),
        gameOver: !!gameState.gameOver,
        endingKey: gameState.endingKey || null
    };
}

// ── public-ish API ────────────────────────────────────────────────────────────

// Persist the current run. Called after every decision / team change / price set.
// No-ops until the founder has actually made a choice, so we never litter the
// picker with untouched blank slates.
function saveCurrentGame() {
    if (!storageAvailable()) return;
    if (!gameState.selectedCards || gameState.selectedCards.length === 0) return;
    if (!currentGameId) currentGameId = genGameId();
    try {
        const blob = { version: SAVE_VERSION, savedAt: Date.now(), state: serializeGameState() };
        localStorage.setItem(SAVE_GAME_PREFIX + currentGameId, JSON.stringify(blob));
        const index = readIndex().filter(s => s.id !== currentGameId);
        index.push(buildSaveSummary(currentGameId));
        writeIndex(index);
    } catch (e) {
        console.warn('Could not save game:', e);
    }
}

// Saves for the picker: only those whose full blob still exists, newest first.
function listSavedGames() {
    if (!storageAvailable()) return [];
    return readIndex()
        .filter(s => s && s.id && localStorage.getItem(SAVE_GAME_PREFIX + s.id))
        .sort((a, b) => new Date(b.savedAt) - new Date(a.savedAt));
}

// Restore a saved business over the current (in-memory) state. Returns false if
// the blob is missing or unreadable so callers can surface the failure.
function loadSavedGame(id) {
    if (!storageAvailable()) return false;
    let blob;
    try {
        const str = localStorage.getItem(SAVE_GAME_PREFIX + id);
        if (!str) return false;
        blob = JSON.parse(str, (key, value) => value === INFINITY_SENTINEL ? Infinity : value);
    } catch (e) {
        return false;
    }
    const state = blob && blob.state ? blob.state : blob; // tolerate a future/legacy flat shape
    replaceGameState(deserializeGameState(state));
    currentGameId = id;
    return true;
}

function deleteSavedGame(id) {
    try { localStorage.removeItem(SAVE_GAME_PREFIX + id); } catch (e) { /* ignore */ }
    writeIndex(readIndex().filter(s => s.id !== id));
    if (currentGameId === id) currentGameId = null;
}

// ── the "Saved Businesses" card (second card) ────────────────────────────────

function escapeHtml(s) {
    return String(s == null ? '' : s).replace(/[&<>"]/g, c =>
        ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' }[c]));
}

function formatSaveMonth(s) {
    // currentMonth can be fractional (0.5-month cards), so round to a whole month
    // and recompute year/month from it — never show a decimal or desync at a year line.
    const absMonth = Math.max(1, Math.round(s.currentMonth));
    const year = Math.floor((absMonth - 1) / 12) + 1;
    const month = ((absMonth - 1) % 12) + 1;
    return year > 1 ? `Y${year} M${month}` : `M${month}`;
}

function savedGameRowHTML(s) {
    // How a failed run reads in the picker, keyed by which ending it hit.
    const failCause = s.endingKey === 'ideaFlop' ? 'Never found traction'
        : (s.endingKey === 'burnout' ? 'Founder burnt out' : 'Ran out of money');
    const failBadge = s.endingKey === 'ideaFlop' ? '💡 Closed'
        : (s.endingKey === 'burnout' ? '🔥 Closed' : '💸 Closed');
    const tag = s.exited
        ? '<span class="saved-game-tag">🎉 Exited</span>'
        : (s.gameOver ? `<span class="saved-game-tag failed">${failBadge}</span>` : '');
    const name = escapeHtml(s.companyName || 'Untitled Startup');
    // Exited businesses are sold; closed (failed) ones are over — both read as a
    // record rather than a live runway. Otherwise show the live runway/revenue.
    let meta;
    if (s.exited) {
        meta = `${formatSaveMonth(s)} · Sold for ${formatMoney(s.exitSalePrice || 0)} · ${s.teamSize} team · ${s.decisions} decisions`;
    } else if (s.gameOver) {
        meta = `${formatSaveMonth(s)} · ${failCause} · ${s.teamSize} team · ${s.decisions} decisions`;
    } else {
        meta = `${formatSaveMonth(s)} · ${formatMoney(s.runway)} runway · ${formatMoney(s.monthlyRevenue)}/mo · ${s.teamSize} team · ${s.decisions} decisions`;
    }
    const loadLabel = s.exited ? 'Buy back' : (s.gameOver ? 'Review' : 'Load');
    return `
        <li class="saved-game-row" data-id="${s.id}" data-name="${name}">
            <div class="saved-game-info">
                <div class="saved-game-name">${name}${tag}</div>
                <div class="saved-game-meta">${meta}</div>
            </div>
            <div class="saved-game-actions">
                <button class="saved-game-load" onclick="loadGameFromCard('${s.id}', this)">${loadLabel}</button>
                <button class="saved-game-delete" onclick="deleteGameFromCard('${s.id}', this)" aria-label="Delete ${name}" title="Delete">✕</button>
            </div>
        </li>`;
}

function generateSavedGamesCard() {
    const rows = listSavedGames().map(savedGameRowHTML).join('');
    // no-swipe keeps it from being flung off by an errant drag (see swipe-cards.js)
    // — the per-row Load buttons and the Start-fresh skip button drive it instead.
    return `
        <div class="business-card no-swipe saved-games-card">
            <div class="card-header opportunity">
                <div class="card-type-wrapper">
                    <div><p>Welcome back</p></div>
                    <div class="card-type">SAVED&nbsp; 💾</div>
                </div>
                <h2>Your Businesses</h2>
            </div>
            <div class="card-body">
                <div style="margin-top: 6px;" class="content-desc">Pick up where you left off. Loading a business replaces the blank slate you're on now.</div>
                <ul class="saved-games-list">${rows}</ul>
                <div class="action-buttons">
                    <button class="btn btn-skip" onclick="skipCard(this)">Start fresh &rarr;</button>
                </div>
            </div>
        </div>`;
}

// ── card button handlers ──────────────────────────────────────────────────────

// Set the company-name button to the restored name. updateCompanyName() picks a
// RANDOM name and is only right for a brand-new game; on resume we keep the saved one.
function applyRestoredCompanyName() {
    if (!domCache.companyName) initDOMCache();
    if (domCache.companyName) domCache.companyName.textContent = gameState.companyName;
}

function loadGameFromCard(id, button) {
    // An exited (sold) business can't just be resumed — the founder has to buy it
    // back at what it sold for, which usually means going into the red.
    const summary = listSavedGames().find(s => s.id === id);
    if (summary && summary.exited) {
        promptBuyBack(id, summary);
        return;
    }
    if (!loadSavedGame(id)) {
        showAlertDialog({
            tone: 'danger',
            icon: '⚠️',
            title: 'Could not load',
            message: 'Sorry — that saved business could not be loaded. Its data may be missing or corrupted.'
        });
        return;
    }
    resumeLoadedGame();
}

// Confirm and apply a buy-back of a sold company: pay the sale price out of its
// own runway (debt allowed), clear the exit, then resume play.
function promptBuyBack(id, summary) {
    const price = summary.exitSalePrice || 0;
    const after = Math.round((summary.runway || 0) - price);
    showConfirmDialog({
        tone: 'founder',
        icon: '↩️',
        title: `Buy back ${summary.companyName || 'this business'}?`,
        rows: [
            ['Reacquisition price', formatMoney(price)],
            ['Runway after', formatMoney(after)]
        ],
        note: after < 0
            ? `Reacquiring costs what it sold for. You'll start ${formatMoney(after)} in the red and have to dig your way back out.`
            : 'Reacquiring costs what it sold for, paid out of the company\'s runway.',
        cancelLabel: 'Cancel',
        confirmLabel: 'Buy back',
        onConfirm: () => {
            if (!loadSavedGame(id)) {
                showAlertDialog({
                    tone: 'danger',
                    icon: '⚠️',
                    title: 'Could not load',
                    message: 'Sorry — that saved business could not be loaded. Its data may be missing or corrupted.'
                });
                return;
            }
            // Apply the repurchase to the now-loaded state: cash out, exit undone.
            gameState.runway -= price;
            gameState.exited = false;
            delete gameState.exitSalePrice;
            recomputeMonthlyRevenue();
            // Mark the outlay on the financial chart so the debt shows immediately.
            if (typeof recordHistorySnapshot === 'function') recordHistorySnapshot(price > 0 ? price : 0);
            saveCurrentGame();
            resumeLoadedGame();
        }
    });
}

// Swap the fresh blank stack out for the just-loaded business and refresh the UI.
// (Instructions is already gone, since the picker had to be the active card to
// click Load.) Shared by a normal load and a buy-back.
function resumeLoadedGame() {
    const container = domCache.simulatorContainer || document.getElementById('simulatorContainer');
    container.querySelectorAll('.business-card').forEach(c => c.remove());
    if (typeof outcomeQueue !== 'undefined' && Array.isArray(outcomeQueue)) outcomeQueue.length = 0;

    applyRestoredCompanyName();
    recomputeMonthlyRevenue();
    updatePriceDisplay();
    updateUI();
    if (typeof updateSelectionsButtonText === 'function') updateSelectionsButtonText();
    // A failed run is terminal: re-show its verdict card rather than dealing fresh
    // cards (loadMoreCards is gated on gameOver and would leave an empty stack).
    if (gameState.gameOver && gameState.endingKey && typeof renderEnding === 'function') {
        renderEnding(gameState.endingKey);
    } else {
        loadMoreCards(4);
    }
    if (typeof updateOpenModals === 'function') updateOpenModals();
}

function deleteGameFromCard(id, button) {
    const row = button.closest('.saved-game-row');
    const list = button.closest('.saved-games-list');
    const name = (row && row.dataset.name) || 'this business';
    showConfirmDialog({
        tone: 'danger',
        icon: '🗑️',
        title: `Delete ${name}?`,
        note: "This permanently removes the saved business. This can't be undone.",
        cancelLabel: 'Keep',
        confirmLabel: 'Delete',
        onConfirm: () => {
            deleteSavedGame(id);
            if (row) row.remove();
            if (list && !list.querySelector('.saved-game-row')) {
                list.innerHTML = '<li class="saved-games-empty">No saved businesses left — start fresh below.</li>';
            }
        }
    });
}

