/* Fullscreen support — two entry points, kept entirely separate from the card
   deck so they can't introduce card-render bugs:

     • Desktop: a persistent toggle button pinned bottom-right (shown only on
       fine-pointer/hover devices via CSS).
     • Touch/small screens: a prompt overlay on load (mirrors the help
       modal — a standalone dialog, NOT a deck card), offering "Go fullscreen"
       or "Not now". Asked once per page load so the player can choose each
       reload (no persistence).

   Note: iOS Safari does not implement the Fullscreen API at all, so when it's
   unsupported we create neither the button nor the prompt — nothing to break. */
(function () {
    const docEl = document.documentElement;

    function fsElement() {
        return document.fullscreenElement || document.webkitFullscreenElement || null;
    }
    function fsSupported() {
        return !!(docEl.requestFullscreen || docEl.webkitRequestFullscreen);
    }
    function enterFullscreen() {
        const req = docEl.requestFullscreen || docEl.webkitRequestFullscreen;
        if (!req) return;
        const p = req.call(docEl);
        if (p && p.catch) p.catch(() => {}); // user-gesture/permission rejections are non-fatal
    }
    function exitFullscreen() {
        const exit = document.exitFullscreen || document.webkitExitFullscreen;
        if (!exit) return;
        const p = exit.call(document);
        if (p && p.catch) p.catch(() => {});
    }
    function toggleFullscreen() {
        if (fsElement()) exitFullscreen(); else enterFullscreen();
    }
    window.toggleFullscreen = toggleFullscreen;

    const ICON_EXPAND =
        '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M8 3H5a2 2 0 0 0-2 2v3M21 8V5a2 2 0 0 0-2-2h-3M3 16v3a2 2 0 0 0 2 2h3M16 21h3a2 2 0 0 0 2-2v-3"/></svg>';
    const ICON_COMPRESS =
        '<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M8 3v3a2 2 0 0 1-2 2H3M21 8h-3a2 2 0 0 1-2-2V3M3 16h3a2 2 0 0 1 2 2v3M16 21v-3a2 2 0 0 1 2-2h3"/></svg>';

    let toggleBtn = null;

    function syncToggleIcon() {
        if (!toggleBtn) return;
        const on = !!fsElement();
        toggleBtn.innerHTML = on ? ICON_COMPRESS : ICON_EXPAND;
        toggleBtn.setAttribute('aria-label', on ? 'Exit fullscreen' : 'Enter fullscreen');
        toggleBtn.setAttribute('aria-pressed', String(on));
        toggleBtn.title = on ? 'Exit fullscreen' : 'Fullscreen';
    }

    function createToggleButton() {
        toggleBtn = document.createElement('button');
        toggleBtn.type = 'button';
        toggleBtn.id = 'fullscreenToggle';
        toggleBtn.className = 'fullscreen-toggle';
        toggleBtn.addEventListener('click', toggleFullscreen);
        document.body.appendChild(toggleBtn);
        syncToggleIcon();
    }

    /* One-time prompt overlay for touch/small screens. Reuses the global
       openDialog/closeDialog focus management and the .help-modal backdrop. */
    function createPrompt() {
        const modal = document.createElement('div');
        modal.className = 'help-modal fs-prompt';
        modal.id = 'fsPrompt';
        modal.setAttribute('role', 'dialog');
        modal.setAttribute('aria-modal', 'true');
        modal.setAttribute('aria-labelledby', 'fsPromptTitle');
        modal.innerHTML = `
            <div class="help-modal-content fs-prompt-content">
                <div class="help-header">
                    <h2 id="fsPromptTitle">📱 Go fullscreen?</h2>
                </div>
                <div class="help-body">
                    <p class="fs-prompt-text">Hide the browser bars for more room to play. You can exit anytime from the menu.</p>
                    <div class="fs-prompt-actions">
                        <button type="button" class="btn btn-skip" id="fsPromptSkip">Not now</button>
                        <button type="button" class="btn btn-select" id="fsPromptGo">Go fullscreen</button>
                    </div>
                </div>
            </div>`;
        document.body.appendChild(modal);

        function dismiss(goFullscreen) {
            if (goFullscreen) enterFullscreen(); // must run inside the click gesture
            if (typeof closeDialog === 'function') closeDialog(modal);
            else modal.remove();
        }
        modal.querySelector('#fsPromptGo').addEventListener('click', () => dismiss(true));
        modal.querySelector('#fsPromptSkip').addEventListener('click', () => dismiss(false));
        return modal;
    }

    function maybeShowPrompt() {
        if (fsElement()) return; // already fullscreen — nothing to ask
        // Touch devices only — desktop gets the corner button instead.
        const isTouch = window.matchMedia('(pointer: coarse)').matches;
        const isSmall = window.matchMedia('(max-width: 767px), (max-height: 640px)').matches;
        if (!isTouch || !isSmall) return;

        const modal = createPrompt();
        if (typeof openDialog === 'function') openDialog(modal);
        else { modal.style.display = 'flex'; setTimeout(() => modal.classList.add('show'), 10); }
    }

    function init() {
        if (!fsSupported()) return; // iOS Safari etc. — skip both entry points
        createToggleButton();
        document.addEventListener('fullscreenchange', syncToggleIcon);
        document.addEventListener('webkitfullscreenchange', syncToggleIcon);
        maybeShowPrompt();
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();

