// main — extracted from biz-sim.js (see CLAUDE.md / js/game)


// Enhanced initialization with better error handling
function initializeSimulator() {
    try {
        initDOMCache();

        // Returning founder who just exited and chose "Start a new business": seed the
        // fresh runway with their take-home proceeds. Handed off via sessionStorage
        // rather than a URL param (which would be trivially editable to cheat), and
        // consumed immediately so it's a true one-time hand-off — a later refresh then
        // behaves like any normal visit (picker shown, no re-seeding).
        let exitProceeds = 0;
        try {
            const stored = sessionStorage.getItem('startupSim:proceeds');
            if (stored) {
                const amount = parseInt(stored, 10);
                if (!isNaN(amount) && amount > 0) {
                    gameState.runway = amount;
                    exitProceeds = amount;
                }
                sessionStorage.removeItem('startupSim:proceeds');
            }
        } catch (e) { /* sessionStorage unavailable — skip the hand-off */ }

        const container = domCache.simulatorContainer;
        if (!container) {
            console.error('Simulator container not found');
            return;
        }
        
        // Add instructions card first, then load the rest of the initial stack
        const instructionsHTML = generateInstructionsCard();
        const instructionsElement = document.createElement('div');
        instructionsElement.innerHTML = instructionsHTML;
        container.appendChild(instructionsElement.firstElementChild);

        // If the founder has saved businesses from a previous visit, surface them on
        // the second card so they can pick up where they left off. Nothing has
        // happened in this fresh session yet, so loading over it is lossless.
        // Skip this when arriving from the exit flow: the founder just sold up and is
        // deliberately starting a new business with their winnings.
        if (!exitProceeds && typeof listSavedGames === 'function' && listSavedGames().length > 0) {
            const savedElement = document.createElement('div');
            savedElement.innerHTML = generateSavedGamesCard();
            container.appendChild(savedElement.firstElementChild);
        }

        loadMoreCards(4);

        updateCompanyName();
        //Calculate metrics for existing selections
        if (gameState.selectedCards.length > 0) {
            recalculateAllMetrics();
        }
        recomputeMonthlyRevenue();
        updatePriceDisplay();
        updateUI();
        // Seed the graph history with a starting baseline so charts have a point
        // to draw from before any decisions are made.
        if (gameState.history.length === 0) {
            recordHistorySnapshot();
        }
        initializeCompanyMetricsModal();
        
        // Add event listeners
        domCache.selectionsBtn?.addEventListener('click', toggleSelectionsModal);

        // Bottom-nav price stepper
        document.getElementById('priceUp')?.addEventListener('click', () => changePrice(PRICE_STEP));
        document.getElementById('priceDown')?.addEventListener('click', () => changePrice(-PRICE_STEP));

        // Modal event listeners
        document.addEventListener('click', (e) => {
            const modal = document.getElementById('selectionsModal');
            if (modal && e.target === modal) {
                closeSelectionsModal();
            }
        });
        
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                closeSelectionsModal();
            }
        });

    } catch (error) {
        console.error('Failed to initialize simulator:', error);
    }
}

// Initialize when DOM is ready
document.addEventListener('DOMContentLoaded', initializeSimulator);

